const CHAT_MODE_EMPHASIS_MARKER_PATTERN = /(?<!\*)\*(?!\*)/g;
const CHAT_MODE_QUOTE_MARKER_PATTERN = /["“”]/g;
const CHAT_MODE_ALL_CAPS_WORD_PATTERN = /^(?=.*[A-Z])[A-Z0-9][A-Z0-9'’\-]*$/;
const CHAT_MODE_MARKDOWN_THEMATIC_BREAK_PATTERN = /^\s{0,3}([*_-])(?:\s*\1){2,}\s*$/;
const CHAT_MODE_MARKDOWN_HEADING_PATTERN = /^\s{0,3}#{1,6}\s+\S/;
const CHAT_MODE_HASH_HEADING_CAPTURE_PATTERN = /^\s{0,3}(#{1,5})\s+(.+?)\s*#*\s*$/;
const CHAT_MODE_MARKDOWN_STRONG_LINE_PATTERN = /^\s*(\*\*|__)\S[\s\S]*\S\1\s*$/;
const CHAT_MODE_PULL_QUOTE_MARKER_PATTERN = /^\s*\[!pull\]\s*/i;
const CHAT_MODE_PULL_QUOTE_INLINE_PREFIX_PATTERN = /^\s*pull\s+quote\s*[:\-–—]\s*/i;
const CHAT_MODE_PULL_QUOTE_INLINE_LINE_PATTERN =
  /^\s*(?:\*\*|__)?\s*pull\s+quote\s*[:\-–—]/i;
const CHAT_MODE_ASSISTANT_MESSAGE_FONT_MIN_PX = 11;
const CHAT_MODE_ASSISTANT_MESSAGE_FONT_MAX_PX = 32;
const CHAT_MODE_USER_MESSAGE_FONT_MIN_PX = 18;
const CHAT_MODE_USER_MESSAGE_FONT_MAX_PX = 40;
const CHAT_MODE_MESSAGE_FONT_MIN_LINES = 1;
const CHAT_MODE_MESSAGE_FONT_MAX_LINES = 18;
const CHAT_MODE_MESSAGE_FONT_DEFAULT_PX = CHAT_MODE_ASSISTANT_MESSAGE_FONT_MIN_PX;
// Curve is inverted in `resolveChatModeMessageFontSizePx`: high progress
// (long messages) maps toward the min, short messages stay near the max.
// Lower exponent = steeper early descent (mid-length messages drop faster
// toward the smaller min), but stays under 1 so the per-line jumps near
// the long end remain small enough that streaming reflow does not jolt
// the auto-scroll target.
const CHAT_MODE_MESSAGE_FONT_CURVE_EXPONENT = 0.6;
const CHAT_MODE_ESTIMATED_WRAP_CHARS_PER_LINE = 34;
const CHAT_MODE_MOOD_WORD_REVEAL_MS: Record<MessageMoodKey, number> = {
  joyful: 95,
  warm: 115,
  neutral: CHAT_MODE_WORD_REVEAL_MS,
  guarded: 170,
  strained: 210,
};
const DEFAULT_CHAT_STARTUP_SUMMARY = "Type a message below to start the conversation.";
const CHAT_MODE_LINE_DISSOLVE_STAGGER_MS = 140;

type ChatModeTypedTokenStyle = "default" | "rainbow";

interface ChatModeTypedTokenMeta {
  style: ChatModeTypedTokenStyle;
  isItalic: boolean;
  isBold: boolean;
  isQuote: boolean;
  noFade: boolean;
  noLetterFade: boolean;
  isEllipsis: boolean;
}

function trimChatModeTokenTrailingWhitespace(token: string): string {
  return token.replace(/\s+$/u, "");
}

function countChatModeStrongMarkers(token: string): number {
  return token.match(CHAT_MODE_STRONG_MARKER_PATTERN)?.length ?? 0;
}

function countChatModeEmphasisMarkers(token: string): number {
  return token.match(CHAT_MODE_EMPHASIS_MARKER_PATTERN)?.length ?? 0;
}

function countChatModeQuoteMarkers(token: string): number {
  return token.match(CHAT_MODE_QUOTE_MARKER_PATTERN)?.length ?? 0;
}

function isQuestionLikeChatTurn(content: string): boolean {
  const trimmed = content.trim();
  if (!trimmed) return false;
  return CHAT_MODE_USER_QUESTION_PATTERN.test(trimmed);
}

function isChatModeEllipsisToken(token: string): boolean {
  return CHAT_MODE_ELLIPSIS_TOKEN_PATTERN.test(token);
}

function formatChatModeTypedTokenDisplay(token: string, isEllipsis: boolean): string {
  const withoutMarkdownMarkers = token
    .replace(CHAT_MODE_STRONG_MARKER_PATTERN, "")
    .replace(CHAT_MODE_EMPHASIS_MARKER_PATTERN, "");
  if (!isEllipsis) return withoutMarkdownMarkers;
  const trailingWhitespace = token.match(/\s+$/u)?.[0] ?? "";
  return `. . .${trailingWhitespace}`;
}

function stripChatModeThematicBreakLines(text: string): string {
  return text
    .replace(/\r\n?/g, "\n")
    .split("\n")
    .map((line) => (CHAT_MODE_MARKDOWN_THEMATIC_BREAK_PATTERN.test(line) ? "" : line))
    .join("\n");
}

function nodeStartsWithPullQuoteMarker(node: React.ReactNode): boolean {
  return CHAT_MODE_PULL_QUOTE_MARKER_PATTERN.test(flattenMarkdownCodeText(node).trimStart());
}

function nodeStartsWithPullQuoteInlinePrefix(node: React.ReactNode): boolean {
  return CHAT_MODE_PULL_QUOTE_INLINE_PREFIX_PATTERN.test(flattenMarkdownCodeText(node).trimStart());
}

function stripLeadingPullQuoteMarker(node: React.ReactNode): React.ReactNode {
  const state = { consumed: false };
  const stripNode = (input: React.ReactNode): React.ReactNode => {
    if (state.consumed || input == null || typeof input === "boolean") return input;
    if (typeof input === "string") {
      const next = input.replace(CHAT_MODE_PULL_QUOTE_MARKER_PATTERN, "");
      if (next !== input) {
        state.consumed = true;
      }
      return next;
    }
    if (typeof input === "number") return input;
    if (Array.isArray(input)) {
      return input.map((entry) => stripNode(entry));
    }
    if (!isValidElement(input)) return input;
    const element = input as React.ReactElement<{ children?: React.ReactNode }>;
    if (!("children" in element.props)) return input;
    const nextChildren = stripNode(element.props.children);
    if (nextChildren === element.props.children) return input;
    return cloneElement(element, { children: nextChildren });
  };
  return stripNode(node);
}

function isChatModeHeadingLikeLine(line: string): boolean {
  const trimmed = line.trim();
  if (!trimmed) return false;
  return (
    CHAT_MODE_MARKDOWN_HEADING_PATTERN.test(line) ||
    CHAT_MODE_MARKDOWN_STRONG_LINE_PATTERN.test(trimmed)
  );
}

function parseChatModeHashHeadingLine(line: string): { level: 1 | 2 | 3; text: string } | null {
  const match = line.match(CHAT_MODE_HASH_HEADING_CAPTURE_PATTERN);
  if (!match) return null;
  const hashes = match[1] ?? "";
  const rawText = (match[2] ?? "").trim();
  if (rawText.length === 0) return null;
  const level = Math.min(3, Math.max(1, hashes.length)) as 1 | 2 | 3;
  return { level, text: rawText };
}

function isChatModePullQuoteInlineLine(line: string): boolean {
  return CHAT_MODE_PULL_QUOTE_INLINE_LINE_PATTERN.test(line.trimStart());
}

function isChatModeAllCapsToken(token: string): boolean {
  const core = trimChatModeTokenTrailingWhitespace(token).replace(/^[^A-Za-z0-9]+|[^A-Za-z0-9]+$/g, "");
  if (core.length <= 1) return false;
  return CHAT_MODE_ALL_CAPS_WORD_PATTERN.test(core);
}

function prismPaletteColorForLetterIndex(index: number): string {
  const paletteLength = PRISM_WORDMARK_PALETTE.length;
  const wrappedIndex = ((index % paletteLength) + paletteLength) % paletteLength;
  return PRISM_WORDMARK_PALETTE[wrappedIndex]!;
}

function resolvePrismHeadingColorVars(): React.CSSProperties {
  return {
    ["--message-heading-color-h1" as string]: PRISM_WORDMARK_PALETTE[0] ?? "#ff5f5f",
    ["--message-heading-color-h2" as string]: PRISM_WORDMARK_PALETTE[1] ?? "#f8c84a",
    ["--message-heading-color-h3" as string]: PRISM_WORDMARK_PALETTE[2] ?? "#6bd97d",
    ["--message-heading-color-h4" as string]: PRISM_WORDMARK_PALETTE[3] ?? "#5cc8ff",
    ["--message-heading-color-h5" as string]: PRISM_WORDMARK_PALETTE[4] ?? "#b07cff",
  } as React.CSSProperties;
}

function resolveComplementHeadingColorVars(
  normalizedBotColor: string,
  resolvedTheme: "light" | "dark"
): React.CSSProperties {
  const baseHue = hexToHsl(normalizedBotColor).h;
  const complementaryHue = (baseHue + 180) % 360;
  const hueOffsets = [0, 12, -12, 24, -24];
  const saturation = resolvedTheme === "light" ? 68 : 78;
  const baseLightness = resolvedTheme === "light" ? 34 : 72;
  const lightnessOffsets = [0, 6, -6, 10, -10];
  const colors = hueOffsets.map((hueOffset, index) => {
    const hue = (complementaryHue + hueOffset + 360) % 360;
    const lightness = Math.max(24, Math.min(82, baseLightness + (lightnessOffsets[index] ?? 0)));
    return hslToHex(hue, saturation, lightness);
  });
  return {
    ["--message-heading-color-h1" as string]: colors[0]!,
    ["--message-heading-color-h2" as string]: colors[1]!,
    ["--message-heading-color-h3" as string]: colors[2]!,
    ["--message-heading-color-h4" as string]: colors[3]!,
    ["--message-heading-color-h5" as string]: colors[4]!,
  } as React.CSSProperties;
}

function resolveChatModeTypedTokenMeta(tokens: string[]): ChatModeTypedTokenMeta[] {
  let insideStrong = false;
  let insideEmphasis = false;
  let insideQuote = false;
  return tokens.map((token) => {
    const strongMarkerCount = countChatModeStrongMarkers(token);
    const isStrongToken = insideStrong || strongMarkerCount > 0;
    if (strongMarkerCount % 2 === 1) {
      insideStrong = !insideStrong;
    }
    const markerCount = countChatModeEmphasisMarkers(token);
    const isEmphasisToken = insideEmphasis || markerCount > 0;
    if (markerCount % 2 === 1) {
      insideEmphasis = !insideEmphasis;
    }
    const quoteMarkerCount = countChatModeQuoteMarkers(token);
    const isQuotedToken = insideQuote || quoteMarkerCount > 0;
    if (quoteMarkerCount % 2 === 1) {
      insideQuote = !insideQuote;
    }
    const ellipsis = isChatModeEllipsisToken(token);
    const allCapsToken = isChatModeAllCapsToken(token);
    const instantRender = allCapsToken;
    const rainbowToken = allCapsToken;
    return {
      style: rainbowToken ? "rainbow" : "default",
      isItalic: isEmphasisToken,
      isBold: isStrongToken,
      isQuote: isQuotedToken,
      noFade: instantRender,
      noLetterFade: instantRender,
      isEllipsis: ellipsis,
    };
  });
}

function messageRequestedAskQuestion(content: string): boolean {
  return ASKQUESTION_INTENT_PATTERN.test(content);
}

function normalizeAskQuestionText(text: string): string {
  return text
    .replace(/\*\*(.*?)\*\*/g, "$1")
    .replace(/__(.*?)__/g, "$1")
    .replace(/`([^`]*)`/g, "$1")
    .replace(/[\p{Extended_Pictographic}\uFE0F]/gu, "")
    .replace(/\s+/g, " ")
    .trim();
}

/**
 * When the model emits long choices like "Title – long explanation…",
 * split on an en/em dash so the chip can show a short title line plus body.
 */
function splitAskQuestionOptionHeading(label: string): { title: string; detail: string | null } {
  const trimmed = label.trim();
  const re = /^(.{8,120}?)\s*[–—]\s+(.+)$/u;
  const m = re.exec(trimmed);
  if (m) {
    const title = m[1].trim();
    const detail = m[2].trim();
    if (title.length > 0 && detail.length > 0) {
      return { title, detail };
    }
  }
  return { title: trimmed, detail: null };
}

function normalizeAskQuestionComparisonText(text: string): string {
  return text
    .replace(/\*\*(.*?)\*\*/g, "$1")
    .replace(/__(.*?)__/g, "$1")
    .replace(/`([^`]*)`/g, "$1")
    .replace(/[\p{Extended_Pictographic}\uFE0F]/gu, "")
    .replace(/[“”"']/g, "")
    .replace(/[\u2013\u2014]/g, "-")
    .replace(/[^\p{L}\p{N}\s\-?:]/gu, " ")
    .replace(/\s+/g, " ")
    .replace(/\s+\?/g, "?")
    .trim()
    .toLowerCase();
}

function lineLooksLikeChooserPromptLineClient(line: string): boolean {
  const t = line.trim();
  if (!t) return false;
  if (/^question\s*[:\-]/i.test(t)) return false;
  if (/^#+\s/.test(t)) return false;
  const n = normalizeAskQuestionComparisonText(t);
  if (!n) return false;
  if (
    /\bwhich (?:option|one|answer) do you choose\b/.test(n) ||
    /\bwhich (?:option|one) (?:would you|will you) (?:pick|choose)\b/.test(n) ||
    /\bwhat(?:'s| is) your (?:pick|choice)\b/.test(n)
  ) {
    return true;
  }
  if (
    /\bpick (?:one|an option)\b/.test(n) ||
    /\bchoose (?:one|an option|from (?:the )?options)\b/.test(n) ||
    /\bselect (?:one|an option)\b/.test(n) ||
    /\btap (?:an )?option\b/.test(n)
  ) {
    return /\?/.test(t);
  }
  if (/\?/.test(t) && t.length <= 56 && /\b(which|pick|choose|select)\b/i.test(t)) {
    if (
      /\b(ratio|shortcake|explain|describe|why|how much|how many|optimal|calculate|define)\b/i.test(
        n
      )
    ) {
      return false;
    }
    return true;
  }
  return false;
}

function refineAskQuestionPayloadFromDisplayClient(
  displayContent: string,
  ask: NonNullable<Message["askQuestion"]>
): NonNullable<Message["askQuestion"]> {
  const lines = displayContent
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter((line) => line.length > 0);

  let chooserFromProse: string | undefined;
  for (let i = lines.length - 1; i >= 0; i -= 1) {
    const line = lines[i]!;
    if (!lineLooksLikeChooserPromptLineClient(line)) continue;
    const cleaned = normalizeAskQuestionText(
      line.replace(
        /^(?:question|prompt|askquestion|ask question|q|heading|title)\s*[:\-]\s*/i,
        ""
      )
    );
    if (cleaned.length > 0) {
      chooserFromProse = cleaned;
      break;
    }
  }

  if (!chooserFromProse) return ask;

  const jsonPromptLooksSubstantive =
    ask.prompt.includes("?") &&
    (ask.prompt.length > 72 || !lineLooksLikeChooserPromptLineClient(ask.prompt));

  if (
    jsonPromptLooksSubstantive ||
    normalizeAskQuestionComparisonText(ask.prompt) !==
      normalizeAskQuestionComparisonText(chooserFromProse)
  ) {
    return { ...ask, prompt: chooserFromProse };
  }
  return ask;
}

function stripAskQuestionFallbackDuplicates(
  content: string,
  askQuestion: NonNullable<Message["askQuestion"]>
): string {
  const promptNorm = normalizeAskQuestionComparisonText(askQuestion.prompt);
  const optionNorms = new Set(
    askQuestion.options
      .map((option) => normalizeAskQuestionComparisonText(option.label))
      .filter((value) => value.length > 0)
  );
  const bridgeLinePatterns: RegExp[] = [
    /\bwhich option do you choose\b/i,
    /\bwhich one do you choose\b/i,
    /\bwhich answer do you choose\b/i,
    /\bchoose one\b/i,
    /\bchoose an option\b/i,
    /\bpick one\b/i,
    /\bselect one\b/i,
    /\btap (?:an )?option\b/i,
    /\bclick (?:an )?option\b/i,
    /\breply with [abc123]\b/i,
    /\brespond with [abc123]\b/i,
  ];
  const optionLeadRegex = /^(?:[-*•]\s*)?(?:option|choice|answer)?\s*(?:[A-Da-d1-4])[)\].:-]\s*/i;

  const compactedLines: string[] = [];
  for (const line of content.split(/\r?\n/)) {
    const norm = normalizeAskQuestionComparisonText(line);
    if (!norm) {
      const previous = compactedLines[compactedLines.length - 1];
      if (previous?.trim().length === 0) continue;
      compactedLines.push(line);
      continue;
    }
    if (norm === promptNorm) continue;
    if (bridgeLinePatterns.some((pattern) => pattern.test(norm))) continue;
    if (optionNorms.has(norm)) continue;
    const lineForEnum = line.replace(/\*\*/g, "");
    const normalizedWithoutMarker = normalizeAskQuestionComparisonText(
      lineForEnum.replace(optionLeadRegex, "")
    );
    if (normalizedWithoutMarker && optionNorms.has(normalizedWithoutMarker)) continue;

    const extraEnum = /^(?:[>*-]\s*)?(?:option\s+)?(?:[DEFdef]|[4-9]|[1-9]\d)[)\].:-]/;
    if (extraEnum.test(line.trim())) {
      const strippedNorm = normalizeAskQuestionComparisonText(
        lineForEnum.replace(optionLeadRegex, "")
      );
      if (strippedNorm.length > 0 && !optionNorms.has(strippedNorm)) {
        continue;
      }
    }

    compactedLines.push(line);
  }
  return compactedLines.join("\n").trim();
}

function extractInlineEnumeratedAskQuestionOptions(content: string): string[] {
  const markerRegex = /(?:^|[\s(])(?:option|choice|answer)?\s*([A-Da-d1-4])[)\].:-]\s*/g;
  const markerMatches: Array<{ order: number; markerStart: number; textStart: number }> = [];

  let match: RegExpExecArray | null;
  while ((match = markerRegex.exec(content)) !== null) {
    const rawMarker = match[1];
    if (!rawMarker) continue;
    const normalizedMarker = rawMarker.toUpperCase();
    const order =
      normalizedMarker === "A"
        ? 1
        : normalizedMarker === "B"
          ? 2
          : normalizedMarker === "C"
            ? 3
            : normalizedMarker === "D"
              ? 4
              : normalizedMarker === "1"
                ? 1
                : normalizedMarker === "2"
                  ? 2
                  : normalizedMarker === "3"
                    ? 3
                    : normalizedMarker === "4"
                      ? 4
                      : -1;
    if (order < 1) continue;

    const startsPrimarySeries = order === 1;
    if (markerMatches.length === 0 && !startsPrimarySeries) continue;
    const previous = markerMatches[markerMatches.length - 1];
    if (previous && order <= previous.order) continue;

    markerMatches.push({
      order,
      markerStart: match.index,
      textStart: markerRegex.lastIndex,
    });
    if (order === 4) break;
  }

  if (markerMatches.length < 3) return [];

  const options: string[] = [];
  for (let i = 0; i < markerMatches.length && options.length < 3; i += 1) {
    const current = markerMatches[i]!;
    const next = markerMatches[i + 1];
    const rawSegment = content.slice(current.textStart, next?.markerStart ?? content.length);
    const cleaned = normalizeAskQuestionText(rawSegment.replace(/\s+/g, " "));
    if (!cleaned) continue;
    options.push(cleaned);
  }

  return options.length >= 3 ? options.slice(0, 3) : [];
}

function assistantLikelyIntendedAskQuestionClient(content: string): boolean {
  const text = content.trim();
  if (!text) return false;
  if (extractDynamicAskQuestion(text)) return true;
  return (
    /\bone block below\b/i.test(text) ||
    /\b(?:choose|pick|select)\s+(?:one|an?\s+option)\b/i.test(text) ||
    /\btap (?:an )?option\b/i.test(text) ||
    /\bmultiple[-\s]?choice\b/i.test(text) ||
    /\breply with [abc123]\b/i.test(text) ||
    /\brespond with [abc123]\b/i.test(text)
  );
}

function extractDynamicAskQuestion(content: string): NonNullable<Message["askQuestion"]> | undefined {
  const lines = content
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter((line) => line.length > 0);
  if (lines.length === 0) return undefined;

  const optionLead = /^(?:[-*•]\s*)?(?:[A-Da-d1-4])[)\].:-]\s*(.+)$/;
  function indexOfFirstPrimaryOption(): number {
    const withMarker = /^(?:[-*•]\s*)?([A-Da-d1-4])[)\].:-]\s*.+$/;
    for (let i = 0; i < lines.length; i += 1) {
      const m = lines[i]!.match(withMarker);
      if (!m?.[1]) continue;
      const marker = m[1]!.toUpperCase();
      if (marker === "A" || m[1] === "1") return i;
    }
    return lines.findIndex((line) => optionLead.test(line));
  }

  const firstOptionIdx = indexOfFirstPrimaryOption();
  if (firstOptionIdx < 0) return undefined;

  let chooserIdx = -1;
  for (let i = lines.length - 1; i >= 0; i -= 1) {
    if (lineLooksLikeChooserPromptLineClient(lines[i]!)) {
      chooserIdx = i;
      break;
    }
  }

  const options: string[] = [];
  const scanEnd = chooserIdx >= 0 ? chooserIdx : lines.length;
  for (let i = firstOptionIdx; i < scanEnd; i += 1) {
    const line = lines[i]!;
    const match = line.match(optionLead);
    if (!match?.[1]) continue;
    const cleaned = normalizeAskQuestionText(match[1]);
    if (cleaned.length === 0) continue;
    options.push(cleaned);
    if (options.length === 3) break;
  }
  if (options.length < 3) {
    const inlineOptions = extractInlineEnumeratedAskQuestionOptions(content);
    if (inlineOptions.length >= 3) {
      options.splice(0, options.length, ...inlineOptions);
    }
  }
  if (options.length < 3) return undefined;

  let chooserText = "";
  if (chooserIdx >= 0) {
    chooserText = normalizeAskQuestionText(lines[chooserIdx] ?? "");
  }
  const prompt =
    chooserText.length > 0 ? chooserText : "Which option fits best?";

  return {
    v: 1,
    name: "AskQuestion",
    prompt,
    options: [
      { id: "a", label: options[0]! },
      { id: "b", label: options[1]! },
      { id: "c", label: options[2]! },
    ],
  };
}

function applyExplicitAskQuestionFallback(
  conversation: ConversationDetail
): ConversationDetail {
  const { messages } = conversation;
  if (!messages || messages.length < 2) return conversation;

  const lastIdx = messages.length - 1;
  const last = messages[lastIdx];
  if (!last || last.role !== "assistant") return conversation;
  if (resolveAssistantAskQuestion(last)) return conversation;

  let previousUser: Message | undefined;
  for (let i = lastIdx - 1; i >= 0; i -= 1) {
    if (messages[i]?.role === "user") {
      previousUser = messages[i];
      break;
    }
  }
  const userExplicitRequest =
    previousUser !== undefined &&
    messageRequestedAskQuestion(previousUser.content);
  const assistantCueRequest = assistantLikelyIntendedAskQuestionClient(last.content);
  if (!userExplicitRequest && !assistantCueRequest) {
    return conversation;
  }

  const dynamic = extractDynamicAskQuestion(last.content);
  if (!dynamic) return conversation;
  let fallbackAskQuestion: NonNullable<Message["askQuestion"]> = dynamic;
  fallbackAskQuestion = refineAskQuestionPayloadFromDisplayClient(
    last.content,
    fallbackAskQuestion
  );
  const patchedLast: Message = {
    ...last,
    content: stripAskQuestionFallbackDuplicates(last.content, fallbackAskQuestion),
    askQuestion: fallbackAskQuestion,
  };
  return {
    ...conversation,
    messages: [...messages.slice(0, lastIdx), patchedLast],
  };
}

function getConversationPendingAskQuestionState(
  messages: Message[] | undefined
): { askQuestion: NonNullable<Message["askQuestion"]>; assistantMessageId: string } | undefined {
  if (!messages || messages.length === 0) return undefined;
  let lastUserIndex = -1;
  for (let i = messages.length - 1; i >= 0; i -= 1) {
    if (messages[i]?.role === "user") {
      lastUserIndex = i;
      break;
    }
  }
  const tail = lastUserIndex < 0 ? messages : messages.slice(lastUserIndex + 1);
  if (tail.some((m) => m.role === "user")) return undefined;

  for (const m of tail) {
    if (m.role !== "assistant") continue;
    const qa = resolveAssistantAskQuestion(m);
    if (qa && qa.name === "AskQuestion" && qa.options.length === 3) {
      return { askQuestion: qa, assistantMessageId: m.id };
    }
  }
  return undefined;
}

function stripEmojiFromAskQuestionLabel(label: string): string {
  const withoutEmoji = label.replace(/[\p{Extended_Pictographic}\uFE0F]/gu, "");
  return withoutEmoji.replace(/\s+/g, " ").trim();
}
type StatusTag = "human" | "local" | "online";

const STATUS_LABEL: Record<StatusTag, string> = {
  human: "HUMAN",
  local: "LOCAL ASSISTANT",
  online: "ONLINE ASSISTANT",
};

function getMessageStatus(msg: Message): StatusTag | null {
  if (msg.role === "user") return "human";
  if (msg.provider === "openai" || msg.provider === "anthropic") return "online";
  if (msg.provider === "local") return "local";
  // Pre-existing assistant messages without a provider record: no indicator.
  return null;
}

function messageUsesConfiguredFallbackModel(args: {
  message: Message;
  view: View;
  configuredFallbackModel: string;
  fallbackMessageIds: Set<string>;
}): boolean {
  if (args.view !== "sandbox") return false;
  if (args.message.role !== "assistant") return false;
  if (args.fallbackMessageIds.has(args.message.id)) return true;
  if (args.message.fallbackUsed === true) return true;
  if (args.configuredFallbackModel.length === 0) return false;
  return args.message.provider === "local" && args.message.model === args.configuredFallbackModel;
}

/** Line shown while the assistant slot is loading — variant index from hash(salt). */
const GENERATING_PHRASE_BUILDERS = [
  (name: string) => `${name} is thinking`,
  (name: string) => `${name} is composing`,
  (name: string) => `${name} is shaping a reply`,
  (name: string) => `${name} is gathering words`,
  (name: string) => `${name} is tuning in`,
  (name: string) => `${name} is reflecting`,
] as const;

