function memoryConfidenceValue(memory: UserMemory): number {
  return Number.isFinite(memory.confidence) ? Math.max(0, Math.min(1, memory.confidence)) : 0.5;
}

function isAssumptionMemory(memory: UserMemory): boolean {
  return memory.source === "inferred" || memory.source === "compiled";
}

function assumptionMemoryOpacity(memory: UserMemory): number {
  const certainty = Number.isFinite(memory.certainty)
    ? Math.max(0, Math.min(1, memory.certainty as number))
    : memoryConfidenceValue(memory);
  return 0.2 + certainty * 0.8;
}

function memoryBubbleSignalValue(memory: UserMemory): number {
  if (!isAssumptionMemory(memory)) return memoryConfidenceValue(memory);
  return Number.isFinite(memory.certainty)
    ? Math.max(0, Math.min(1, memory.certainty as number))
    : memoryConfidenceValue(memory);
}

const MEMORY_BUBBLE_DEDUP_EPSILON = 0.0001;
const MEMORY_DUPLICATE_CONFIDENCE_MAX_BOOST = 0.22;
const MEMORY_DUPLICATE_CONFIDENCE_BOOST_DECAY = 0.62;

function normalizeMemoryBubbleDedupKey(text: string): string {
  return text.trim().replace(/\s+/g, " ").toLocaleLowerCase();
}

function chooseMemoryBubbleRepresentative(current: UserMemory, candidate: UserMemory): UserMemory {
  const currentSignal = memoryBubbleSignalValue(current);
  const candidateSignal = memoryBubbleSignalValue(candidate);
  if (candidateSignal > currentSignal + MEMORY_BUBBLE_DEDUP_EPSILON) return candidate;
  if (currentSignal > candidateSignal + MEMORY_BUBBLE_DEDUP_EPSILON) return current;

  const currentDurability = Number.isFinite(current.durability)
    ? Math.max(0, Math.min(1, current.durability as number))
    : 0;
  const candidateDurability = Number.isFinite(candidate.durability)
    ? Math.max(0, Math.min(1, candidate.durability as number))
    : 0;
  if (candidateDurability > currentDurability + MEMORY_BUBBLE_DEDUP_EPSILON) return candidate;
  if (currentDurability > candidateDurability + MEMORY_BUBBLE_DEDUP_EPSILON) return current;

  const currentCreatedAtMs = Date.parse(current.createdAt);
  const candidateCreatedAtMs = Date.parse(candidate.createdAt);
  if (Number.isFinite(candidateCreatedAtMs) && Number.isFinite(currentCreatedAtMs)) {
    if (candidateCreatedAtMs > currentCreatedAtMs) return candidate;
    if (currentCreatedAtMs > candidateCreatedAtMs) return current;
  }

  return current;
}

function applyDuplicateConfidenceBoost(memory: UserMemory, duplicateCount: number): UserMemory {
  if (duplicateCount <= 1) return memory;
  const baseSignal = memoryBubbleSignalValue(memory);
  const boostProgress = 1 - Math.pow(MEMORY_DUPLICATE_CONFIDENCE_BOOST_DECAY, duplicateCount - 1);
  const boostedSignal = Math.max(
    0,
    Math.min(
      1,
      baseSignal + (1 - baseSignal) * MEMORY_DUPLICATE_CONFIDENCE_MAX_BOOST * boostProgress
    )
  );
  if (isAssumptionMemory(memory)) {
    return {
      ...memory,
      confidence: boostedSignal,
      certainty: boostedSignal,
    };
  }
  return {
    ...memory,
    confidence: boostedSignal,
  };
}

function estimateMemoryDurabilityForDisplay(text: string): number {
  const normalized = text.trim();
  if (!normalized) return 0.25;
  let score = 0.46;
  const cat = classifyMemoryCategoryFromText(normalized);
  if (cat === "user") score += 0.16;
  if (cat === "bot_relation") score += 0.18;
  const durablePatternHits = [
    /\b(?:always|never|do not|don't|like|likes|love|loves|enjoy|enjoys|prefer|prefers|favorite|favourite|need|needs|want|wants|value|values|care about|cares about)\b/i,
    /\b(?:identity|personality|character|believes?|principles?|boundary|boundaries|comfort|safe|safety)\b/i,
    /\b(?:sees|treats|uses|understands)\s+.+\s+as\s+/i,
    /\b(?:born|founded|created|developed|built|grew|became|known for|signature|method|career|company|inc\.?|workshops?|instructors?|instructional|materials?|art supplies)\b/i,
  ].reduce((count, pattern) => count + (pattern.test(normalized) ? 1 : 0), 0);
  if (durablePatternHits > 0) {
    score += Math.min(0.44, durablePatternHits * 0.24);
  }
  if (/\b(?:remember|don't forget|do not forget|keep in mind|make a note)\b/i.test(normalized) || /\b[A-Z][A-Za-z'.-]+(?:\s+[A-Z][A-Za-z'.-]+){1,3}\b/.test(normalized)) {
    score += 0.3;
  }
  if (/\b(?:currently|today|right now|this moment|for now|temporarily|seems|might|maybe|probably)\b/i.test(normalized)) {
    score -= 0.22;
  }
  return Math.max(0.1, Math.min(1, score));
}

function memoryTier(memory: UserMemory): MemoryTier {
  const confidence = Number.isFinite(memory.confidence) ? Math.max(0, Math.min(1, memory.confidence)) : 0;
  const certainty = Number.isFinite(memory.certainty) ? Math.max(0, Math.min(1, memory.certainty as number)) : confidence;
  const estimatedDurability = estimateMemoryDurabilityForDisplay(memory.text);
  const storedDurability = Number.isFinite(memory.durability)
    ? Math.max(0, Math.min(1, memory.durability as number))
    : 0;
  const durability = Math.max(storedDurability, estimatedDurability);
  return memory.tier === "long_term" ||
    memoryQualifiesLongTerm({
      confidence,
      certainty,
      durability,
      source: memory.source ?? "direct",
    })
    ? "long_term"
    : "short_term";
}

function memoryCategory(memory: UserMemory): MemoryCategory {
  if (memory.category === "general" || memory.category === "user" || memory.category === "bot_relation") {
    return memory.category;
  }
  return memory.botId ? classifyMemoryCategoryFromText(memory.text) : "user";
}

function toPossessiveLabel(label: string): string {
  const trimmed = label.trim();
  if (!trimmed) return "User's";
  return trimmed.endsWith("s") ? `${trimmed}'` : `${trimmed}'s`;
}

function toThirdPersonVerb(verb: string): string {
  const lower = verb.toLowerCase();
  const irregular = new Map<string, string>([
    ["am", "is"],
    ["are", "is"],
    ["were", "was"],
    ["have", "has"],
    ["do", "does"],
  ]);
  const irregularMatch = irregular.get(lower);
  if (irregularMatch) return irregularMatch;
  const doNotTransform = new Set([
    "can",
    "can't",
    "cannot",
    "could",
    "couldn't",
    "did",
    "didn't",
    "does",
    "doesn't",
    "had",
    "has",
    "is",
    "might",
    "must",
    "shall",
    "should",
    "shouldn't",
    "was",
    "will",
    "won't",
    "would",
    "wouldn't",
  ]);
  if (doNotTransform.has(lower)) return lower;
  if (lower.endsWith("ies") || lower.endsWith("s")) return lower;
  if (lower.endsWith("y") && lower.length > 1 && !/[aeiou]y$/.test(lower)) {
    return `${lower.slice(0, -1)}ies`;
  }
  if (/(ch|sh|x|z|o)$/.test(lower)) return `${lower}es`;
  return `${lower}s`;
}

function formatMemoryPanelText(
  text: string,
  subjectLabel: string,
  category: MemoryCategory
): string {
  const normalized = text.trim();
  if (!normalized) return normalized;
  if (category !== "user") return normalized;
  const subject = subjectLabel.trim() || "User";
  const possessive = toPossessiveLabel(subject);
  const subjectPattern = subject.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const rewritten = normalized
    .replace(/^the user's\b/i, possessive)
    .replace(/^user's\b/i, possessive)
    .replace(/^your\b/i, possessive)
    .replace(/^the user\b/i, subject)
    .replace(/^user\b/i, subject)
    .replace(/^you(?:'re| are)\b/i, `${subject} is`)
    .replace(/^you(?:'ve| have)\b/i, `${subject} has`)
    .replace(/^you(?:'d| would)\b/i, `${subject} would`)
    .replace(/^you(?:'ll| will)\b/i, `${subject} will`)
    .replace(/^you don't\b/i, `${subject} doesn't`)
    .replace(/^you do\b/i, `${subject} does`)
    .replace(/^you were\b/i, `${subject} was`)
    .replace(/^you\b/i, subject);

  const lead = rewritten.match(new RegExp(`^${subjectPattern}\\s+([A-Za-z']+)\\b`, "i"));
  const verb = lead?.[1];
  if (!verb) return rewritten;
  const thirdPerson = toThirdPersonVerb(verb);
  return rewritten.replace(
    new RegExp(`^(${subjectPattern}\\s+)${verb}\\b`, "i"),
    `$1${thirdPerson}`
  );
}

function stableUnitValue(seed: string): number {
  let hash = 2166136261;
  for (let i = 0; i < seed.length; i += 1) {
    hash ^= seed.charCodeAt(i);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0) / 0xffffffff;
}

/**
 * Floating orbit dots for zoomed-out PRISM directory bubbles — one dot per bot
 * (up to {@link MEMORY_FAMILY_BOT_INNER_DOT_MAX}), matching the drill-down bot orbs.
 */
function buildFamilyDirectoryBotInnerBubbles(
  familyId: string,
  botCount: number,
  familySizePx: number
): MemoryClusterInnerBubble[] {
  if (botCount <= 0) return [];
  const capped = Math.min(botCount, MEMORY_FAMILY_BOT_INNER_DOT_MAX);
  const orbitScale = Math.max(0.38, Math.min(1.12, familySizePx / MEMORY_RATIO_LARGE_MAX_SIZE));
  const placed: Array<{ x: number; y: number; radius: number }> = [];
  const bubbles: MemoryClusterInnerBubble[] = [];
  const density = Math.min(1, capped / Math.max(1, MEMORY_FAMILY_BOT_INNER_DOT_MAX));

  for (let i = 0; i < capped; i += 1) {
    const size = 3.8 + density * 2.6 + ((i + capped) % 3) * 0.95;
    const radius = size / 2;
    const minCenterRadius = (9 + radius) * orbitScale;
    const maxCenterRadius = Math.max(minCenterRadius + 1, (30 - radius) * orbitScale);
    let candidate: { x: number; y: number; radius: number } | null = null;

    for (let attempt = 0; attempt < 48; attempt += 1) {
      const angle = stableUnitValue(`family:${familyId}:bot-dot:${i}:a:${attempt}`) * Math.PI * 2;
      const radialSeed = stableUnitValue(`family:${familyId}:bot-dot:${i}:r:${attempt}`);
      const radialT = Math.pow(radialSeed, 0.36);
      const distance = minCenterRadius + radialT * (maxCenterRadius - minCenterRadius);
      const x = Math.cos(angle) * distance;
      const y = Math.sin(angle) * distance;
      const overlaps = placed.some((other) => {
        const dx = x - other.x;
        const dy = y - other.y;
        const minDistance = radius + other.radius + 2;
        return dx * dx + dy * dy < minDistance * minDistance;
      });
      if (!overlaps) {
        candidate = { x, y, radius };
        break;
      }
    }

    if (!candidate) {
      const fallbackAngle = ((i * 137.50776405) % 360) * (Math.PI / 180);
      const fallbackDistance = Math.min(maxCenterRadius, 12 + i * 1.85);
      candidate = {
        x: Math.cos(fallbackAngle) * fallbackDistance,
        y: Math.sin(fallbackAngle) * fallbackDistance,
        radius,
      };
    }

    placed.push(candidate);
    bubbles.push({
      id: `${familyId}-family-bot-${i}`,
      style: {
        ["--memory-inner-x" as string]: `${candidate.x.toFixed(2)}px`,
        ["--memory-inner-y" as string]: `${candidate.y.toFixed(2)}px`,
        ["--memory-inner-size" as string]: `${size.toFixed(2)}px`,
        ["--memory-inner-dx" as string]: `${(
          (stableUnitValue(`family:${familyId}:bot-dot:${i}:dx`) - 0.5) *
          6
        ).toFixed(2)}px`,
        ["--memory-inner-dy" as string]: `${(
          (stableUnitValue(`family:${familyId}:bot-dot:${i}:dy`) - 0.5) *
          6
        ).toFixed(2)}px`,
        ["--memory-inner-duration" as string]: `${(
          2.8 + stableUnitValue(`family:${familyId}:bot-dot:${i}:dur`) * 2.2
        ).toFixed(2)}s`,
        ["--memory-inner-delay" as string]: `${(i * 0.14).toFixed(2)}s`,
      } as React.CSSProperties,
    });
  }

  return bubbles;
}

// Build a left-to-right gradient from up to N bot colors in a group so
// each editor dashboard button reads as an ordered slice of its bucket's
// actual spectrum. Stops are color-mixed against `--bg` so the tile still
// feels like a calm card.
// Returns null when no bot has a usable color.
function buildBotGroupGradient(
  groupBots: readonly Bot[],
  theme: "light" | "dark",
  harmonyActive: boolean,
  mixPercent: number
): string | null {
  if (groupBots.length === 0) return null;
  const sampleSize = Math.min(groupBots.length, 6);
  const stride = groupBots.length / sampleSize;
  const stops: string[] = [];
  for (let i = 0; i < sampleSize; i++) {
    const idx = Math.min(groupBots.length - 1, Math.floor(i * stride));
    const bot = groupBots[idx];
    const accent = bot.color
      ? panelBotDisplayAccent(bot.color, theme, harmonyActive)
      : null;
    if (!accent) continue;
    stops.push(
      `color-mix(in srgb, ${accent} ${mixPercent}%, var(--bg) ${100 - mixPercent}%)`
    );
  }
  if (stops.length === 0) return null;
  if (stops.length === 1) return stops[0];
  return `linear-gradient(to right, ${stops.join(", ")})`;
}

// Map a hex color to one of the five Prism letter buckets. Hue cuts
// mirror botColorFamilyGroup but collapse adjacent fine-grained
// families into the closest wordmark letter so the dashboard reads
// as the Prism color family the user already sees in the brand mark.
// Invalid/grayscale legacy colors still classify by hue so every bot
// can find a home in one of the five letters — randomHex() prevents
// new bots from ever being grayscale in the first place.
function botPrismGroup(hex: string | null | undefined): PrismGroupId {
  const raw = hex?.trim();
  if (!raw || !hexChannels(raw)) return "p";
  const { h } = hexToHsl(raw);
  if (h >= 315) return "p";
  if (h < 15) return "p";
  if (h < 75) return "r"; // orange + yellow
  if (h < 165) return "i"; // lime + green
  if (h < 245) return "s"; // cyan + blue
  return "m"; // indigo + violet + magenta-leaning purple
}

// Accent color for new bots defaults to randomHex() via component state on
// first paint. Subsequent random seeds run only when the Bots panel opens
// in create mode before the user has typed anything — closing the panel and
// reopening preserves picks + text (see bots-panel seed useEffect below).
interface ImageRecord {
  id: string;
  prompt: string;
  url: string;
  createdAt: string;
  botId?: string | null;
  /** Prefer for rendering — points at authenticated `/api/images/:id/file` when durably stored. */
  displayUrl?: string;
  hasLocalFile?: boolean;
  revisedPrompt?: string | null;
  size?: string;
  quality?: string;
  provider?: string;
  model?: string | null;
  localRelPath?: string | null;
  purpose?: "gallery" | "wallpaper" | string | null;
}

/** Authenticated WebP thumbnail for a locally stored generated image (`images.id`). */
function apiGeneratedImageThumbUrl(imageId: string): string {
  return `/api/images/${encodeURIComponent(imageId)}/thumb`;
}

/** Images panel grid tile: prefer `/thumb` for local files; remote-only rows keep full URL. */
function galleryTileImageSrc(img: ImageRecord): string {
  if (img.hasLocalFile === true) {
    return apiGeneratedImageThumbUrl(img.id);
  }
  return img.displayUrl ?? img.url;
}

/** Short label for gallery thumbnails — catalog match when possible, else raw id. */
function galleryImageThumbModelLabel(
  img: ImageRecord,
  localCatalog: ModelCatalogEntry[],
  openAiCatalog: ModelCatalogEntry[]
): string {
  const raw = img.model?.trim();
  if (!raw) return "Unknown model";
  const catalog = img.provider === "openai" ? openAiCatalog : localCatalog;
  return catalog.find((e) => e.id === raw)?.label ?? raw;
}

type ImagePanelScope = "all" | "bot" | "general";

type ScopedImageKeywords = {
  positive: string[];
  negative: string[];
};

type ImageKeywordDragMode = "add" | "remove";

const IMAGE_KEYWORD_CHIP_ROW_GAP_PX = 4;
const IMAGE_KEYWORD_CHIP_BASE_WIDTH_PX = 26;
const IMAGE_KEYWORD_CHIP_CHAR_WIDTH_PX = 7.1;
const IMAGE_KEYWORD_CHIP_MIN_PACK_WIDTH_PX = 120;
const IMAGE_KEYWORD_EDITOR_KINDS = ["negative", "positive"] as const;

/** Sandbox hero mini library: newest saved images for the visually selected bot. */
const HERO_MINI_LIBRARY_MAX_TILES = 12;

const EMPTY_SCOPED_IMAGE_KEYWORDS: ScopedImageKeywords = {
  positive: [],
  negative: [],
};

function estimateImageKeywordChipWidthPx(tag: string): number {
  const normalizedLength = tag.trim().length;
  return Math.max(
    56,
    Math.round(IMAGE_KEYWORD_CHIP_BASE_WIDTH_PX + normalizedLength * IMAGE_KEYWORD_CHIP_CHAR_WIDTH_PX)
  );
}

function buildPackedImageKeywordDisplayOrder(
  tags: string[],
  containerWidthPx: number,
  measuredChipWidths: Record<string, number>
): string[] {
  if (tags.length <= 2) return tags.slice();
  const rowCapacity = Math.max(IMAGE_KEYWORD_CHIP_MIN_PACK_WIDTH_PX, Math.floor(containerWidthPx));
  if (rowCapacity <= IMAGE_KEYWORD_CHIP_MIN_PACK_WIDTH_PX) return tags.slice();
  const weighted = tags
    .map((tag, index) => ({
      tag,
      index,
      width: measuredChipWidths[tag] ?? estimateImageKeywordChipWidthPx(tag),
    }))
    .sort((left, right) => right.width - left.width || left.index - right.index);
  const pool = weighted.slice();
  const rows: Array<{ tags: string[] }> = [];
  while (pool.length > 0) {
    const anchor = pool.shift();
    if (!anchor) break;
    const rowTags = [anchor.tag];
    let remainingWidth = Math.max(0, rowCapacity - anchor.width);
    while (pool.length > 0) {
      const neededForGap = rowTags.length > 0 ? IMAGE_KEYWORD_CHIP_ROW_GAP_PX : 0;
      const allowedWidth = remainingWidth - neededForGap;
      if (allowedWidth <= 0) break;
      let candidateIndex = -1;
      // Back-fill gaps with smaller chips first.
      for (let index = pool.length - 1; index >= 0; index -= 1) {
        const candidate = pool[index];
        if (!candidate) continue;
        if (candidate.width <= allowedWidth) {
          candidateIndex = index;
          break;
        }
      }
      if (candidateIndex < 0) break;
      const [picked] = pool.splice(candidateIndex, 1);
      if (!picked) break;
      rowTags.push(picked.tag);
      remainingWidth = Math.max(0, remainingWidth - (picked.width + neededForGap));
    }
    rows.push({
      tags: rowTags,
    });
  }
  return rows.flatMap((row) => row.tags);
}

const DEFAULT_ASSISTANT_NAME = "Prism";
const PRISM_MESSAGE_ROLE_LETTERS = ["P", "R", "I", "S", "M"] as const;
const DEFAULT_MESSAGE_MOOD: NonNullable<Message["moodKey"]> = "neutral";

function normalizeAssistantMoodKey(
  moodKey: Message["moodKey"] | undefined
): NonNullable<Message["moodKey"]> {
  if (
    moodKey === "joyful" ||
    moodKey === "warm" ||
    moodKey === "neutral" ||
    moodKey === "guarded" ||
    moodKey === "strained"
  ) {
    return moodKey;
  }
  return DEFAULT_MESSAGE_MOOD;
}

function messageHasCustomBotIdentity(message: Message): boolean {
  return Boolean(
    message.botName?.trim() ||
    message.botColor?.trim() ||
    message.botGlyph?.trim()
  );
}

function shouldRenderPrismMessageRoleLabel(message: Message, incognito: boolean): boolean {
  return (
    message.role === "assistant" &&
    !incognito &&
    !messageHasCustomBotIdentity(message)
  );
}

function PrismMessageRoleLabel(): React.JSX.Element {
  return (
    <span className={styles.prismMessageRoleLabel}>
      <span className={styles.messageRoleVisuallyHidden}>
        {DEFAULT_ASSISTANT_NAME}
      </span>
      <span className={styles.prismMessageRoleLetters} aria-hidden="true">
        {PRISM_MESSAGE_ROLE_LETTERS.map((letter) => (
          <span
            key={letter}
            className={styles.prismMessageRoleLetter}
          >
            {letter}
          </span>
        ))}
      </span>
    </span>
  );
}

function resolveMessageMoodKey(message: Message): NonNullable<Message["moodKey"]> {
  if (message.role !== "assistant") return DEFAULT_MESSAGE_MOOD;
  return normalizeAssistantMoodKey(message.moodKey);
}

function messageMoodLabel(moodKey: NonNullable<Message["moodKey"]>): string {
  switch (moodKey) {
    case "joyful":
      return "Joyful";
    case "warm":
      return "Warm";
    case "guarded":
      return "Guarded";
    case "strained":
      return "Strained";
    default:
      return "Neutral";
  }
}

function MessageMoodFace(props: {
  moodKey: NonNullable<Message["moodKey"]>;
  variant?: "classic" | "prism";
  placement?: "leading" | "trailing";
}): React.JSX.Element {
  const variant = props.variant ?? "classic";
  const placement = props.placement ?? "trailing";
  const moodKey = props.moodKey;
  const mouthByMood: Record<NonNullable<Message["moodKey"]>, string> = {
    joyful: "M7.5 15.5 Q12 21 16.5 15.5",
    warm: "M8 15 Q12 18.5 16 15",
    neutral: "M8 16 H16",
    guarded: "M8 17.2 Q12 14.4 16 17.2",
    strained: "M8 18 Q12 12.8 16 18",
  };
  const eyesByMood: Record<NonNullable<Message["moodKey"]>, [string, string]> = {
    joyful: ["M8.2 10.7 Q9.2 9.7 10.2 10.7", "M13.8 10.7 Q14.8 9.7 15.8 10.7"],
    warm: ["M8.2 10.9 Q9.2 10 10.2 10.9", "M13.8 10.9 Q14.8 10 15.8 10.9"],
    neutral: ["M8.2 11 H10.2", "M13.8 11 H15.8"],
    guarded: ["M8.2 11.3 H10.1", "M13.9 11.3 H15.8"],
    strained: ["M8.2 11.8 H10", "M14 11.8 H15.8"],
  };
  const browByMood: Partial<Record<NonNullable<Message["moodKey"]>, string>> = {
    guarded: "M7 8.5 L10 7.4 M14 7.4 L17 8.5",
    strained: "M7 9.2 L10 7 M14 7 L17 9.2",
  };
  if (variant === "classic") {
    const browPath = browByMood[moodKey];
    const [leftEyePath, rightEyePath] = eyesByMood[moodKey];
    return (
      <span
        className={styles.messageMoodBadge}
        data-mood={moodKey}
        data-placement={placement}
        aria-hidden="true"
      >
        <svg
          className={styles.messageMoodFace}
          viewBox="0 0 24 24"
          role="img"
          focusable="false"
          aria-hidden="true"
        >
          <circle className={styles.messageMoodFaceBase} cx="12" cy="12" r="9" />
          <path className={styles.messageMoodFeature} d={leftEyePath} />
          <path className={styles.messageMoodFeature} d={rightEyePath} />
          {browPath ? <path className={styles.messageMoodFeature} d={browPath} /> : null}
          <path className={styles.messageMoodFeature} d={mouthByMood[moodKey]} />
        </svg>
      </span>
    );
  }
  // The Prism face keeps a stable primitive set across moods (ring + brows +
  // eyes + mouth) so these paths can be tweened later without redesigning topology.
  const faceByMood: Record<
    NonNullable<Message["moodKey"]>,
    {
      leftBrow: string;
      rightBrow: string;
      leftEye: string;
      rightEye: string;
      mouth: string;
    }
  > = {
    joyful: {
      leftBrow: "M7.3 8.3 Q8.8 7.7 10.2 8.2",
      rightBrow: "M13.8 8.2 Q15.2 7.7 16.7 8.3",
      leftEye: "M7.7 10.7 Q9 9.4 10.3 10.7",
      rightEye: "M13.7 10.7 Q15 9.4 16.3 10.7",
      mouth: "M7.4 14.9 Q12 19.1 16.6 14.9",
    },
    warm: {
      leftBrow: "M7.4 8.7 Q8.8 8.1 10.2 8.6",
      rightBrow: "M13.8 8.6 Q15.2 8.1 16.6 8.7",
      leftEye: "M7.8 10.9 Q9 9.9 10.2 10.9",
      rightEye: "M13.8 10.9 Q15 9.9 16.2 10.9",
      mouth: "M7.8 15.4 Q12 18 16.2 15.4",
    },
    neutral: {
      leftBrow: "M7.5 8.9 H10.1",
      rightBrow: "M13.9 8.9 H16.5",
      leftEye: "M7.9 11 H10.1",
      rightEye: "M13.9 11 H16.1",
      mouth: "M8.2 15.8 H15.8",
    },
    guarded: {
      leftBrow: "M7.1 8.9 L10.1 7.8",
      rightBrow: "M13.9 7.8 L16.9 8.9",
      leftEye: "M7.8 11.4 H10",
      rightEye: "M14 11.4 H16.2",
      mouth: "M8.1 16.8 Q12 14.7 15.9 16.8",
    },
    strained: {
      leftBrow: "M7.1 9.4 L10.1 7.2",
      rightBrow: "M13.9 7.2 L16.9 9.4",
      leftEye: "M7.9 11.8 L10 10.6",
      rightEye: "M14 10.6 L16.1 11.8",
      mouth: "M8.1 17.6 Q10.3 14.8 12 17.4 Q13.7 14.8 15.9 17.6",
    },
  };
  const face = faceByMood[moodKey];
  return (
    <span
      className={styles.messageMoodBadge}
      data-mood={moodKey}
      data-placement={placement}
      aria-hidden="true"
    >
      <svg
        className={styles.messageMoodFace}
        viewBox="0 0 24 24"
        role="img"
        focusable="false"
        aria-hidden="true"
      >
        {/* Neutral shell keeps the badge legible in both themes. */}
        <circle
          cx="12"
          cy="12"
          r="8.9"
          fill="none"
          stroke="currentColor"
          strokeOpacity="0.2"
          strokeWidth="1.7"
        />
        {/* PRISM segmented ring (P/R/I/S/M) to match hub glyph methodology. */}
        <path d="M12 3.2 A8.8 8.8 0 0 1 18.3 5.8" stroke={PRISM_COLORS.p} strokeWidth="1.8" strokeLinecap="round" />
        <path d="M19.4 7.2 A8.8 8.8 0 0 1 20.8 12" stroke={PRISM_COLORS.r} strokeWidth="1.8" strokeLinecap="round" />
        <path d="M20.6 14 A8.8 8.8 0 0 1 16.9 18.9" stroke={PRISM_COLORS.i} strokeWidth="1.8" strokeLinecap="round" />
        <path d="M15.1 20 A8.8 8.8 0 0 1 8.9 20" stroke={PRISM_COLORS.s} strokeWidth="1.8" strokeLinecap="round" />
        <path
          d="M7.1 18.9 A8.8 8.8 0 0 1 3.4 12 A8.8 8.8 0 0 1 8 5.4"
          stroke={PRISM_COLORS.m}
          strokeWidth="1.8"
          strokeLinecap="round"
        />
        <path className={styles.messageMoodFeature} d={face.leftBrow} style={{ stroke: PRISM_COLORS.p }} />
        <path className={styles.messageMoodFeature} d={face.rightBrow} style={{ stroke: PRISM_COLORS.r }} />
        <path className={styles.messageMoodFeature} d={face.leftEye} style={{ stroke: PRISM_COLORS.i }} />
        <path className={styles.messageMoodFeature} d={face.rightEye} style={{ stroke: PRISM_COLORS.s }} />
        <path className={styles.messageMoodFeature} d={face.mouth} style={{ stroke: PRISM_COLORS.m }} />
      </svg>
    </span>
  );
}

// PRISM fallback for non-private Default/no-bot surfaces that still need a
// single accent token. Private/incognito remains the only monochrome path.
const PRISM_DEFAULT_ACCENT = PRISM_COLORS.s;

function neutralRowColor(resolvedTheme: "light" | "dark"): string {
  return resolvedTheme === "dark" ? "#ffffff" : "#000000";
}

// Resolve a sidebar conversation row's custom-bot tint color from the server-side
// denormalized `lastBotColor`. Default/no-bot chats are handled separately so
// they can keep the same row-gradient structure with a neutral black/white tint.
//
// Order matters:
//   1. Incognito wins — private rows never pick up a hue (grayscale
//      styling comes from the private-row CSS, not from this resolver).
//   2. `lastBotColor` is the server's denormalized color at the time it
//      responded, so it stays correct even if the bot was later deleted
//      or recolored.
//   3. `hasAssistantReply && !lastBotColor` means the last reply came
//      from the Default bot (no bot_id) — no custom hue.
//   4. `botId` → live bots[] lookup. Catches the pre-reply window where
//      a conversation has a locked bot but no assistant message yet.
//   5. No locked bot and no reply either — no custom hue.
function resolveRowColor(
  c: ConversationSummary,
  bots: Bot[]
): string | null {
  if (c.incognito) return null;
  if (c.lastBotColor) return c.lastBotColor;
  if (c.hasAssistantReply) return null;
  if (c.botId) {
    const live = bots.find((b) => b.id === c.botId)?.color;
    if (live) return live;
  }
  return null;
}

function conversationGroupKey(c: ConversationSummary): string {
  const effectiveBotId = conversationEffectiveBotId(c);
  return effectiveBotId ? `bot:${effectiveBotId}` : "default";
}

function conversationEffectiveBotId(c: ConversationSummary): string | null {
  // Group rows by the same "active identity" users see in sidebar tinting:
  // - after at least one assistant reply, follow the last speaking bot
  // - before first reply, fall back to the conversation's locked starter bot
  return c.hasAssistantReply ? c.lastBotId : c.botId;
}

/** Mirror of `conversationGroupKey` for cases where only the bot id is in
 *  hand — e.g. picking a panel to auto-open after a new chat is committed. */
function conversationGroupKeyForBotId(botId: string): string {
  return `bot:${botId}`;
}

function conversationGroupBotId(key: string): string | null {
  return key.startsWith("bot:") ? key.slice("bot:".length) : null;
}

function conversationGroupDeleteKey(key: string): string {
  return `group:${key}`;
}

/** Namespaces a single chat row delete in `pendingDeleteKey` (sidebar ×). */
function conversationRowDeleteKey(conversationId: string): string {
  return `chatdel:${conversationId}`;
}

/** HTML `id` slug — `group.key` may contain `:` (e.g. `bot:uuid`). */
function conversationGroupDomSafeSlug(key: string): string {
  return key.replace(/[^a-zA-Z0-9_-]/g, "_");
}

function conversationGroupNestedListId(key: string): string {
  return `conversation-group-chats-${conversationGroupDomSafeSlug(key)}`;
}

function conversationGroupHeaderButtonId(key: string): string {
  return `conversation-group-toggle-${conversationGroupDomSafeSlug(key)}`;
}

function conversationGroupOrderStorageKey(userId: string): string {
  return `${CONVERSATION_GROUP_ORDER_STORAGE_KEY}:${userId}`;
}

function botLibraryGroupsStorageKey(userId: string): string {
  return `${BOT_LIBRARY_GROUPS_STORAGE_KEY}:${userId}`;
}

function commandCenterStateStorageKey(userId: string): string {
  return `${COMMAND_CENTER_STATE_STORAGE_KEY}:${userId}`;
}

function loadConversationGroupOrder(userId: string): string[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = window.localStorage.getItem(conversationGroupOrderStorageKey(userId));
    const parsed: unknown = raw ? JSON.parse(raw) : [];
    return Array.isArray(parsed)
      ? parsed.filter((key): key is string => typeof key === "string")
      : [];
  } catch {
    return [];
  }
}

function persistConversationGroupOrder(userId: string, order: string[]): void {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.setItem(
      conversationGroupOrderStorageKey(userId),
      JSON.stringify(order)
    );
  } catch {
    // Non-fatal: drag ordering still works for the current page session.
  }
}

function reorderConversationGroupKeys(
  currentOrder: string[],
  draggedKey: string,
  targetKey: string,
  position: ConversationGroupDropPosition
): string[] {
  if (draggedKey === targetKey) return currentOrder;
  const withoutDragged = currentOrder.filter((key) => key !== draggedKey);
  const targetIndex = withoutDragged.indexOf(targetKey);
  if (targetIndex === -1) return currentOrder;
  const insertIndex = position === "after" ? targetIndex + 1 : targetIndex;
  return [
    ...withoutDragged.slice(0, insertIndex),
    draggedKey,
    ...withoutDragged.slice(insertIndex),
  ];
}

function buildConversationGroupSummary(
  key: string,
  conversations: ConversationSummary[],
  bots: Bot[],
  unreadConversationIds: Set<string>
): ConversationGroupSummary {
  const botId = conversationGroupBotId(key);
  const bot = botId ? bots.find((candidate) => candidate.id === botId) : null;
  const fallbackColor =
    conversations.find((conversation) => conversation.lastBotColor)?.lastBotColor ?? null;
  return {
    key,
    botId,
    name: bot?.name?.trim() || (botId ? "Deleted bot" : DEFAULT_ASSISTANT_NAME),
    glyph: bot
      ? isBotGlyphName(bot.glyph)
        ? bot.glyph
        : DEFAULT_BOT_GLYPH
      : "triangle",
    color: bot?.color ?? fallbackColor,
    count: conversations.length,
    conversations,
    latestUpdatedAt: conversations[0]?.updatedAt ?? "",
    unread: conversations.some((conversation) => unreadConversationIds.has(conversation.id)),
  };
}

function buildConversationGroups(
  conversations: ConversationSummary[],
  bots: Bot[],
  unreadConversationIds: Set<string>
): ConversationGroupSummary[] {
  const grouped = new Map<string, ConversationSummary[]>();
  for (const conversation of conversations) {
    const key = conversationGroupKey(conversation);
    const existing = grouped.get(key);
    if (existing) {
      if (!existing.some((c) => c.id === conversation.id)) {
        existing.push(conversation);
      }
    } else {
      grouped.set(key, [conversation]);
    }
  }
  return [...grouped.entries()]
    .filter(([, rows]) => rows.length > 0)
    .map(([key, rows]) =>
      buildConversationGroupSummary(key, rows, bots, unreadConversationIds)
    );
}

function ThemeGlyph({ mode }: { mode: Theme }): React.ReactElement {
  // Stroke-only 16x16 glyphs that take their color from currentColor, so the
  // same button can shift between muted/hover/locked hues purely via CSS.
  // Matches the lock glyph's visual weight (14px glyph inside a 30px button).
  return (
    <svg
      className={styles.themeToggleGlyph}
      viewBox="0 0 16 16"
      aria-hidden="true"
    >
      {mode === "light" && (
        <>
          {/* Sun: central disc + 8 radial rays. */}
          <circle cx="8" cy="8" r="3" suppressHydrationWarning />
          <path
            d="M8 1v2M8 13v2M1 8h2M13 8h2M3 3l1.5 1.5M11.5 11.5l1.5 1.5M3 13l1.5-1.5M11.5 4.5l1.5-1.5"
            suppressHydrationWarning
          />
        </>
      )}
      {mode === "dark" && (
        /* Crescent moon: one arc carved out of a larger one. */
        <path
          d="M13 9A5.5 5.5 0 1 1 7 3a4.5 4.5 0 0 0 6 6Z"
          suppressHydrationWarning
        />
      )}
      {mode === "system" && (
        <>
          {/* Half-filled circle: outline the full disc, then fill the right
             hemisphere so it reads as "sun on one side, moon on the other". */}
          <circle cx="8" cy="8" r="5.5" suppressHydrationWarning />
          <path
            d="M8 2.5A5.5 5.5 0 0 1 8 13.5Z"
            fill="currentColor"
            stroke="none"
            suppressHydrationWarning
          />
        </>
      )}
    </svg>
  );
}

