const THEME_LABEL: Record<Theme, string> = {
  light: "Light",
  dark: "Dark",
  system: "Auto",
};

function nextThemeMode(current: Theme): Theme {
  if (current === "light") return "dark";
  if (current === "dark") return "system";
  return "light";
}

function isPrimaryPointerDismissal(event: MouseEvent | PointerEvent): boolean {
  // Dismiss on normal primary clicks/taps, and also on desktop context-menu
  // gestures (right-click / Ctrl+click) so users can close menus without an
  // extra left-click.
  const isMouseEvent = !("pointerType" in event) || event.pointerType === "mouse";
  if (isMouseEvent && (event.button === 2 || (event.ctrlKey && event.button === 0))) {
    return true;
  }
  return event.button === 0;
}

function authHeadersForFetch(): HeadersInit {
  let nativeSessionToken: string | null = null;
  let clientAccessToken: string | null = null;
  if (typeof window !== "undefined") {
    try {
      nativeSessionToken = window.localStorage.getItem(NATIVE_SESSION_STORAGE_KEY);
      clientAccessToken = window.localStorage.getItem(CLIENT_ACCESS_STORAGE_KEY);
    } catch {
      nativeSessionToken = null;
      clientAccessToken = null;
    }
  }
  return {
    ...(nativeSessionToken ? { authorization: `Bearer ${nativeSessionToken}` } : {}),
    ...(clientAccessToken ? { "x-prism-client-access": clientAccessToken } : {}),
  };
}

async function fetchAuthenticated(path: string, init?: RequestInit): Promise<Response> {
  return fetch(path, {
    credentials: "include",
    headers: {
      ...authHeadersForFetch(),
      ...(init?.headers ?? {}),
    },
    ...init,
  });
}

function sanitizeForFilenameSegment(raw: string): string {
  const cleaned = raw.replace(/[^\w.-]+/g, "_").replace(/^_+|_+$/g, "");
  return cleaned.length > 0 ? cleaned.slice(0, 96) : "image";
}

async function downloadBotImageFile(
  img: ImageRecord,
  botDisplayName: string,
): Promise<void> {
  const path = img.displayUrl ?? img.url;
  const res = await fetchAuthenticated(path);
  if (!res.ok) {
    const raw = await res.text();
    let message = raw.trim() || `Download failed (${res.status})`;
    try {
      const payload = JSON.parse(raw) as { error?: string };
      if (payload.error) message = payload.error;
    } catch {
      // Keep constructed message when body is not JSON.
    }
    throw new Error(message);
  }
  const blob = await res.blob();
  const stamp = sanitizeForFilenameSegment(
    (img.createdAt ?? img.id).replace(/[:.]/g, "-"),
  );
  const nameBase = sanitizeForFilenameSegment(botDisplayName);
  const filename = `prism-${nameBase}-image-${stamp}.png`;
  const url = URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = url;
  anchor.download = filename;
  anchor.rel = "noopener";
  document.body.appendChild(anchor);
  anchor.click();
  anchor.remove();
  URL.revokeObjectURL(url);
}

function formatImageGenElapsed(seconds: number): string {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${String(s).padStart(2, "0")}`;
}

/** True when `fetch` was aborted (user cancel or navigation). */
function isAbortLikeError(err: unknown): boolean {
  if (!(err instanceof Error)) return false;
  if (err.name === "AbortError") return true;
  return (
    typeof DOMException !== "undefined" &&
    err instanceof DOMException &&
    err.name === "AbortError"
  );
}

/** Transport-layer failures hide behind vague messages or bare `TypeError` on some browsers. */
function looksLikeDisconnectedFetchFailure(err: unknown, path: string): boolean {
  const top = err instanceof Error ? err.message : String(err ?? "");
  const cause =
    err instanceof Error &&
    typeof err === "object" &&
    err.cause !== undefined &&
    err.cause !== null &&
    err.cause instanceof Error
      ? err.cause.message
      : "";
  const lowered = `${top} ${cause}`.toLowerCase();
  const isApiPath = typeof path === "string" && path.startsWith("/api");
  if (
    lowered.includes("fetch failed") ||
    lowered.includes("failed to fetch") ||
    lowered.includes("networkerror") ||
    lowered.includes("network request failed") ||
    lowered.includes("load failed") ||
    lowered.includes("unable to fetch") ||
    lowered.includes("connection refused") ||
    lowered.includes("econnrefused") ||
    lowered.includes("econnreset")
  )
    return true;
  if (!isApiPath || !(err instanceof TypeError)) return false;
  if (!top.trim()) return true;
  return (
    lowered.includes("fetch") ||
    lowered.includes("network") ||
    lowered.includes("load") ||
    lowered.includes("failed")
  );
}

function prismApiTransportHint(path: string, rawMsg: string): Error {
  const origin =
    typeof window !== "undefined" ? window.location.origin : "the Prism web app";
  return new Error(
    `Lost connection loading ${path} from ${origin}. Start the Prism API (default http://127.0.0.1:18787) or fix LOCALAI_API_ORIGIN where you run Next. (${rawMsg})`
  );
}

async function api<T>(path: string, options?: RequestInit): Promise<T> {
  const headers: HeadersInit = {
    "content-type": "application/json",
    ...authHeadersForFetch(),
    ...(options?.headers ?? {}),
  };
  const requestUrl =
    typeof window !== "undefined" &&
    typeof path === "string" &&
    path.startsWith("/") &&
    !path.startsWith("//")
      ? new URL(path, window.location.origin).href
      : path;
  let res: Response;
  try {
    res = await fetch(requestUrl, {
      credentials: "include",
      headers,
      ...options,
    });
  } catch (err) {
    if (isAbortLikeError(err)) throw err;
    const rawMsg =
      err instanceof Error ? `${err.message || err.name}`.trim() : String(err ?? "");
    if (looksLikeDisconnectedFetchFailure(err, path)) {
      throw prismApiTransportHint(path, rawMsg || "network");
    }
    throw err instanceof Error ? err : new Error(rawMsg);
  }
  // Next rewrite failures can come back as plain text, so parse the body
  // defensively and surface the actual message instead of a JSON parse error.
  let raw: string;
  try {
    raw = await res.text();
  } catch (err) {
    if (isAbortLikeError(err)) throw err;
    const rawMsg =
      err instanceof Error ? `${err.message || err.name}`.trim() : String(err ?? "");
    if (looksLikeDisconnectedFetchFailure(err, path)) {
      throw prismApiTransportHint(path, rawMsg || "response body interrupted");
    }
    throw err instanceof Error ? err : new Error(rawMsg);
  }
  let payload: (T & { ok?: boolean; error?: string }) | null = null;
  if (raw.trim().length > 0) {
    try {
      payload = JSON.parse(raw) as T & { ok?: boolean; error?: string };
    } catch {
      payload = null;
    }
  }
  if (!res.ok || payload?.ok === false) {
    const fallbackMessage = raw.trim() || `Request failed (${res.status})`;
    throw new Error(payload?.error ?? fallbackMessage);
  }
  return (payload ?? {}) as T;
}

async function writeClipboardText(text: string): Promise<void> {
  if (navigator.clipboard && window.isSecureContext) {
    try {
      await navigator.clipboard.writeText(text);
      return;
    } catch {
      // Fall through to the legacy path below; LAN dev over plain HTTP is not
      // always treated as a secure context even when the user explicitly clicks.
    }
  }

  const textarea = document.createElement("textarea");
  textarea.value = text;
  textarea.setAttribute("readonly", "true");
  textarea.style.position = "fixed";
  textarea.style.left = "-9999px";
  textarea.style.top = "0";
  document.body.appendChild(textarea);
  textarea.focus();
  textarea.select();

  try {
    const copied = document.execCommand("copy");
    if (!copied) {
      throw new Error("Clipboard copy command failed.");
    }
  } finally {
    textarea.remove();
  }
}

function clearNativeSessionToken(): void {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.removeItem(NATIVE_SESSION_STORAGE_KEY);
  } catch {
    // Non-fatal: cookie-backed browser auth can still continue normally.
  }
}

