  // Keep the dim backdrop visual, but let pointer events hit underlying
  // messages so right-click/tap can immediately retarget the context menu.
  // Dismissal is handled centrally by outside-click capture.
  useEffect(() => {
    if (!messageContextMenu) return;
    const onPointerDownCapture = (event: PointerEvent) => {
      if (!isPrimaryPointerDismissal(event)) return;
      const node = event.target as Node | null;
      const menuRoot = messageActionsMenuRef.current;
      if (node && menuRoot?.contains(node)) return;
      const focusRoot =
        typeof document !== "undefined"
          ? document.querySelector("[data-msg-mobile-focus-root='true']")
          : null;
      if (node && focusRoot?.contains(node)) return;
      closeMessageContextOverlay();
    };
    document.addEventListener("pointerdown", onPointerDownCapture, true);
    return () =>
      document.removeEventListener("pointerdown", onPointerDownCapture, true);
  }, [messageContextMenu, closeMessageContextOverlay]);

  const openMessageContextMenu = useCallback(
    (
      msg: Message,
      x: number,
      y: number,
      opts?: {
        anchor?: MessageMenuAnchor;
        mobileActivate?: boolean;
      }
    ) => {
      const anchor: MessageMenuAnchor = opts?.anchor ?? "pointer";
      const minY = anchor === "below" ? 64 : 96;
      const maxY = anchor === "below" ? window.innerHeight - 120 : window.innerHeight - 96;
      const pointerPosition =
        anchor === "pointer"
          ? clampContextMenuPosition(
              x,
              y,
              MESSAGE_CONTEXT_MENU_ESTIMATED_WIDTH_PX,
              MESSAGE_CONTEXT_MENU_ESTIMATED_HEIGHT_PX
            )
          : null;
      const resolvedX = pointerPosition
        ? pointerPosition.x
        : Math.min(Math.max(x, 88), window.innerWidth - 88);
      const resolvedY = pointerPosition
        ? pointerPosition.y
        : Math.min(Math.max(y, minY), maxY);
      setMessageContextMenu({
        message: msg,
        x: resolvedX,
        y: resolvedY,
        anchor,
      });
      setBotContextMenu(null);
      setConversationGroupContextMenu(null);
      setCanvasToolsContextMenu(null);
      setContextFocusedMessageId(msg.id);
      setModelRevealMessageId(msg.role === "assistant" ? msg.id : null);

      const vpMobile = viewportWidth <= PICKER_MOBILE_BREAKPOINT;
      if (opts?.mobileActivate && vpMobile) {
        setMobileFocusedMessageId(msg.id);
      }
    },
    [viewportWidth]
  );

  async function exportChat() {
    if (!selectedId) return;
    const d = await api<{ markdown: string }>(`/api/conversations/${selectedId}/export`, { method: "POST", body: "{}" });
    const blob = new Blob([d.markdown], { type: "text/markdown" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a"); a.href = url; a.download = `chat-${selectedId}.md`; a.click(); URL.revokeObjectURL(url);
  }

  async function exportCoffeeSession(conversation: CoffeeConversationState | null): Promise<void> {
    if (!conversation) return;
    if (coffeeSessionPhase !== "finished") return;
    const data = await api<{ markdown: string }>(
      `/api/conversations/${encodeURIComponent(conversation.id)}/export`,
      { method: "POST", body: "{}" }
    );
    const slug = slugifyFileToken(conversation.title || "coffee-session");
    const blob = new Blob([data.markdown], { type: "text/markdown" });
    const url = URL.createObjectURL(blob);
    const anchor = document.createElement("a");
    anchor.href = url;
    anchor.download = `${slug}.md`;
    anchor.click();
    URL.revokeObjectURL(url);
  }

  function slugifyFileToken(input: string): string {
    return input
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/^-+|-+$/g, "")
      .slice(0, 48) || "bot";
  }

  function extractBotExportJson(raw: string): string {
    const trimmed = raw.trim();
    const fenced = trimmed.match(/```(?:json)?\s*([\s\S]*?)```/i);
    if (fenced?.[1]) return fenced[1].trim();
    const firstBrace = trimmed.indexOf("{");
    const lastBrace = trimmed.lastIndexOf("}");
    if (firstBrace >= 0 && lastBrace > firstBrace) {
      return trimmed.slice(firstBrace, lastBrace + 1);
    }
    return trimmed;
  }

  function parseImportBotLoadingHint(raw: string): {
    name: string | null;
    color: string | null;
    glyph: BotGlyphName;
  } {
    try {
      const parsedUnknown = JSON.parse(extractBotExportJson(raw));
      if (typeof parsedUnknown !== "object" || parsedUnknown === null || Array.isArray(parsedUnknown)) {
        return { name: null, color: null, glyph: DEFAULT_BOT_GLYPH };
      }
      const parsed = parsedUnknown as {
        bot?: { name?: unknown; color?: unknown; glyph?: unknown };
      };
      const rawName = typeof parsed.bot?.name === "string" ? parsed.bot.name.trim() : "";
      const rawColor = typeof parsed.bot?.color === "string" ? parsed.bot.color.trim() : "";
      const rawGlyph = typeof parsed.bot?.glyph === "string" ? parsed.bot.glyph.trim() : "";
      const color = /^#?[0-9a-fA-F]{6}$/.test(rawColor)
        ? (rawColor.startsWith("#") ? rawColor : `#${rawColor}`)
        : null;
      const glyph = isBotGlyphName(rawGlyph) ? rawGlyph : DEFAULT_BOT_GLYPH;
      return {
        name: rawName.length > 0 ? rawName : null,
        color,
        glyph,
      };
    } catch {
      return { name: null, color: null, glyph: DEFAULT_BOT_GLYPH };
    }
  }

  async function buildBotExportFile(bot: Bot): Promise<{
    trimmedName: string;
    exportHash: string | null;
    memoriesCount: number;
    json: string;
  }> {
    const trimmedName = bot.name.trim() || "Unnamed bot";
    let exportHash = normalizeImportedBotHash(bot.export_hash);
    if (!exportHash) {
      const generatedHash = createClientBotExportHash();
      try {
        await api(`/api/bots/${encodeURIComponent(bot.id)}`, {
          method: "PATCH",
          body: JSON.stringify({ exportHash: generatedHash }),
        });
        exportHash = generatedHash;
        setBots((list) =>
          list.map((candidate) =>
            candidate.id === bot.id
              ? { ...candidate, export_hash: generatedHash }
              : candidate
          )
        );
      } catch {
        // Keep export working even if this bot cannot be patched (e.g. stale/public row).
        exportHash = generatedHash;
      }
    }
    const profile = parseStoredBotPrompt(bot.system_prompt).fields;
    const visiblePrompt = stripBotProfileMetaSuffix(bot.system_prompt).trim();
    const memoryResult = await api<{
      memories?: Array<{
        text?: string;
        confidence?: number;
        category?: MemoryCategory;
        tier?: MemoryTier;
        source?: "direct" | "inferred" | "compiled" | "about_you";
        certainty?: number;
        durability?: number;
        sourceMessageIds?: string[];
      }>;
    }>(`/api/memories?botId=${encodeURIComponent(bot.id)}`);
    const memories: BotExportMemory[] = (memoryResult.memories ?? [])
      .filter((memory): memory is {
        text: string;
        confidence?: number;
        category?: MemoryCategory;
        tier?: MemoryTier;
        source?: "direct" | "inferred" | "compiled" | "about_you";
        certainty?: number;
        durability?: number;
        sourceMessageIds?: string[];
      } => typeof memory.text === "string" && memory.text.trim().length > 0)
      .map((memory) => ({
        text: memory.text.trim(),
        confidence: memory.confidence,
        category: memory.category,
        tier: memory.tier,
        source: memory.source,
        certainty: memory.certainty,
        durability: memory.durability,
        sourceMessageIds: Array.isArray(memory.sourceMessageIds) ? memory.sourceMessageIds : [],
      }));
    const exportPayload: BotExportPayloadV1 = {
      schema: "prism-bot-export-v1",
      botHash: exportHash ?? undefined,
      bot: {
        name: trimmedName,
        color: bot.color ?? null,
        glyph: bot.glyph ?? null,
        temperature: bot.temperature,
        maxTokens: bot.max_tokens,
        localModel: bot.local_model ?? bot.model ?? null,
        onlineModel: bot.online_model ?? null,
        localImageModel: bot.local_image_model ?? null,
        openaiImageModel: bot.openai_image_model ?? null,
        onlineEnabled: bot.online_enabled === 1,
        flirtEnabled: bot.flirt_enabled === 1,
        chatEnabled: bot.chat_enabled === 1,
        deleteProtected: bot.delete_protected === 1,
      },
      profile,
      systemPrompt: visiblePrompt,
      memories,
      exportedAt: new Date().toISOString(),
    };
    return {
      trimmedName,
      exportHash,
      memoriesCount: memories.length,
      json: `${JSON.stringify(exportPayload, null, 2)}\n`,
    };
  }

  async function exportBotProfile(bot: Bot) {
    setPanelError(null);
    setPanelNotice(null);
    const built = await buildBotExportFile(bot);
    const blob = new Blob([built.json], { type: "application/json;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `bot-${slugifyFileToken(built.trimmedName)}.bot`;
    a.click();
    URL.revokeObjectURL(url);
    setPanelNotice(
      built.memoriesCount > 0
        ? `${built.trimmedName} exported with ${built.memoriesCount} memories.`
        : `${built.trimmedName} exported.`
    );
  }

  async function exportBotsAsZip(selectedBots: Bot[]): Promise<void> {
    if (selectedBots.length === 0) return;
    setPanelError(null);
    setPanelNotice(null);
    const files: Record<string, Uint8Array> = {};
    const usedNames = new Set<string>();
    let totalMemories = 0;
    for (const bot of selectedBots) {
      const built = await buildBotExportFile(bot);
      totalMemories += built.memoriesCount;
      const base = `bot-${slugifyFileToken(built.trimmedName)}`;
      let candidate = `${base}.bot`;
      let suffix = 2;
      while (usedNames.has(candidate)) {
        candidate = `${base}-${suffix}.bot`;
        suffix += 1;
      }
      usedNames.add(candidate);
      files[candidate] = strToU8(built.json);
    }
    const zipped = zipSync(files, { level: 6 });
    const blob = new Blob([zipped], { type: "application/zip" });
    const url = URL.createObjectURL(blob);
    const anchor = document.createElement("a");
    const stamp = new Date().toISOString().replace(/[:.]/g, "-");
    anchor.href = url;
    anchor.download = `bots-${selectedBots.length}-${stamp}.zip`;
    anchor.click();
    URL.revokeObjectURL(url);
    setPanelNotice(
      totalMemories > 0
        ? `${selectedBots.length} bots exported to ZIP with ${totalMemories} memories.`
        : `${selectedBots.length} bots exported to ZIP.`
    );
  }

  async function exportAccountAsPrismArchive(): Promise<void> {
    setPanelError(null);
    setPanelNotice(null);
    setAccountBackupBusy(true);
    try {
      const response = await api<{ snapshot?: unknown }>("/api/backup/export");
      if (!response.snapshot) {
        throw new Error("Backup export did not return snapshot data.");
      }
      const exportedAt = new Date().toISOString();
      const bundle: AccountExportBundleV1 = {
        schema: "prism-account-backup-v1",
        exportedAt,
        snapshot: response.snapshot,
      };
      const files: Record<string, Uint8Array> = {
        "backup.json": strToU8(`${JSON.stringify(bundle, null, 2)}\n`),
      };
      const zipped = zipSync(files, { level: 6 });
      const blob = new Blob([zipped], { type: "application/zip" });
      const url = URL.createObjectURL(blob);
      const anchor = document.createElement("a");
      const stamp = exportedAt.replace(/[:.]/g, "-");
      anchor.href = url;
      anchor.download = `prism-account-${stamp}.prism`;
      anchor.click();
      URL.revokeObjectURL(url);
      setPanelNotice("Account backup exported as .prism.");
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Account export failed.");
    } finally {
      setAccountBackupBusy(false);
    }
  }

  function parseAccountSnapshotFromJson(raw: string): unknown {
    let parsed: unknown;
    try {
      parsed = JSON.parse(stripOptionalLeadingUtf8Bom(raw));
    } catch {
      throw new Error("Could not read .prism backup JSON.");
    }
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
      throw new Error("Backup file is not a valid JSON object.");
    }
    const record = parsed as Record<string, unknown>;
    if (record.schema === "prism-account-backup-v1") {
      if (!("snapshot" in record)) {
        throw new Error("Backup file is missing snapshot data.");
      }
      return record.snapshot;
    }
    if (record.version === 1 && Array.isArray(record.conversations) && Array.isArray(record.memories)) {
      return record;
    }
    throw new Error("Unsupported .prism backup format.");
  }

  async function importAccountFromPrismFile(file: File): Promise<void> {
    const archiveBytes = new Uint8Array(await file.arrayBuffer());
    let entries: Record<string, Uint8Array>;
    try {
      entries = unzipSync(archiveBytes);
    } catch {
      throw new Error("Could not read .prism archive.");
    }
    const preferredEntry = Object.entries(entries).find(
      ([name]) => name.trim().toLowerCase() === "backup.json"
    );
    const fallbackEntry = Object.entries(entries).find(
      ([name]) => name.trim().toLowerCase().endsWith(".json")
    );
    const jsonEntry = preferredEntry ?? fallbackEntry;
    if (!jsonEntry) {
      throw new Error(".prism file does not contain a JSON backup payload.");
    }
    const snapshot = parseAccountSnapshotFromJson(strFromU8(jsonEntry[1]));
    await api("/api/backup/import", {
      method: "POST",
      body: JSON.stringify({ snapshot }),
    });
    await refreshAll();
    setPanelNotice("Account backup imported.");
  }

  async function handleAccountImportFileSelection(
    event: React.ChangeEvent<HTMLInputElement>
  ): Promise<void> {
    const file = event.currentTarget.files?.[0];
    event.currentTarget.value = "";
    if (!file) return;
    if (!file.name.trim().toLowerCase().endsWith(".prism")) {
      setPanelError("Only .prism files can be imported here.");
      return;
    }
    setPanelError(null);
    setPanelNotice(null);
    setAccountRestoreBusy(true);
    try {
      await importAccountFromPrismFile(file);
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Account import failed.");
    } finally {
      setAccountRestoreBusy(false);
    }
  }

  function openAccountImportPicker(): void {
    setPanelError(null);
    setPanelNotice(null);
    queueMicrotask(() => {
      accountImportInputRef.current?.click();
    });
  }

  function parseBotExportPayload(raw: string): Partial<BotExportPayloadV1> {
    const normalized = stripOptionalLeadingUtf8Bom(raw);
    if (botImportUtf8ByteLength(normalized) > BOT_IMPORT_EXPORT_RAW_MAX_UTF8_BYTES) {
      throw new Error(
        `That export is too large to import here (max ${Math.round(BOT_IMPORT_EXPORT_RAW_MAX_UTF8_BYTES / 1024)} KB).`
      );
    }
    let parsedUnknown: unknown;
    try {
      parsedUnknown = JSON.parse(extractBotExportJson(normalized));
    } catch {
      throw new Error("Could not read JSON — check braces, quotes, and trailing commas.");
    }
    if (typeof parsedUnknown !== "object" || parsedUnknown === null || Array.isArray(parsedUnknown)) {
      throw new Error("Bot import must be a single JSON object (not a list or bare value).");
    }
    const parsed = parsedUnknown as Partial<BotExportPayloadV1>;
    if (parsed.schema !== "prism-bot-export-v1" || !parsed.bot?.name) {
      throw new Error("Invalid bot export file.");
    }
    return parsed;
  }

  async function importBotFromExportRawText(
    raw: string,
    options?: ImportBotOptions
  ): Promise<ImportBotResult> {
    if (!options?.suppressPanelReset) {
      setPanelError(null);
      setPanelNotice(null);
    }
    const parsed = parseBotExportPayload(raw);
    const importedBotHash = normalizeImportedBotHash(parsed.botHash);
    if (
      importedBotHash &&
      !options?.allowDuplicateHash &&
      bots.some((candidate) => normalizeImportedBotHash(candidate.export_hash) === importedBotHash)
    ) {
      throw new Error("This bot is already in your library!");
    }
    const parsedBot = parsed.bot;
    if (!parsedBot) {
      throw new Error("Invalid bot export file.");
    }
    const importedName = parsedBot.name.trim();
    if (!importedName) {
      throw new Error("Bot export is missing a valid name.");
    }

    const fallbackProfile = blankBotProfile();
    const hasStructuredProfile =
      parsed.profile !== null
      && typeof parsed.profile === "object"
      && !Array.isArray(parsed.profile);
    const profile = hasStructuredProfile
      ? parseStoredBotPrompt(
        serializeStoredBotPrompt(parsed.profile as BotProfileFields, importedName)
      ).fields
      : fallbackProfile;
    const importedVisiblePrompt =
      typeof parsed.systemPrompt === "string" ? parsed.systemPrompt.trim() : "";
    const systemPrompt = hasStructuredProfile
      ? serializeStoredBotPrompt(profile, importedName)
      : importedVisiblePrompt || serializeStoredBotPrompt(profile, importedName);

    const created = await api<{ bot?: { id?: string } }>("/api/bots", {
      method: "POST",
      body: JSON.stringify({
        name: importedName,
        systemPrompt,
        localModel: parsedBot.localModel ?? "",
        onlineModel: parsedBot.onlineModel ?? "",
        localImageModel:
          typeof parsedBot.localImageModel === "string"
            ? parsedBot.localImageModel
            : "",
        openaiImageModel:
          typeof parsedBot.openaiImageModel === "string"
            ? parsedBot.openaiImageModel
            : "",
        onlineEnabled: parsedBot.onlineEnabled !== false,
        flirtEnabled: parsedBot.flirtEnabled === true,
        chatEnabled: parsedBot.chatEnabled !== false,
        deleteProtected: parsedBot.deleteProtected === true,
        temperature:
          typeof parsedBot.temperature === "number"
            ? normalizeBotTemperature(parsedBot.temperature)
            : BOT_TEMPERATURE_DEFAULT,
        maxTokens:
          typeof parsedBot.maxTokens === "number"
            ? normalizeBotMaxTokens(parsedBot.maxTokens)
            : BOT_REPLY_LENGTH_DEFAULT_TOKENS,
        color: typeof parsedBot.color === "string" && parsedBot.color.trim().length > 0
          ? parsedBot.color.trim()
          : null,
        glyph: typeof parsedBot.glyph === "string" && parsedBot.glyph.trim().length > 0
          ? parsedBot.glyph.trim()
          : null,
        exportHash: importedBotHash,
      }),
    });
    const createdBotId = created.bot?.id;
    if (!createdBotId) {
      throw new Error("Imported bot was created without an id.");
    }

    const memories = Array.isArray(parsed.memories) ? parsed.memories : [];
    let restored = 0;
    for (const memory of memories) {
      if (!memory || typeof memory.text !== "string" || memory.text.trim().length === 0) continue;
      const source = normalizeImportedMemorySource(memory.source);
      const category = normalizeImportedMemoryCategory(memory.category);
      await api("/api/memories/restore", {
        method: "POST",
        body: JSON.stringify({
          text: memory.text.trim(),
          botId: createdBotId,
          source,
          confidence:
            typeof memory.confidence === "number" ? memory.confidence : undefined,
          category,
          tier:
            memory.tier === "long_term" || memory.tier === "short_term"
              ? memory.tier
              : undefined,
          certainty:
            typeof memory.certainty === "number" ? memory.certainty : undefined,
          durability:
            typeof memory.durability === "number" ? memory.durability : undefined,
          sourceMessageIds: Array.isArray(memory.sourceMessageIds)
            ? memory.sourceMessageIds
            : [],
        }),
      });
      restored += 1;
    }

    await refreshBots();
    await refreshMemories();
    await refreshBotMemories(createdBotId);
    if (options?.selectInChat !== false) {
      selectImportedBotInChatMode(createdBotId);
    }
    if (!options?.suppressNotice) {
      setPanelNotice(
        restored > 0
          ? `${importedName} imported with ${restored} memories.`
          : `${importedName} imported.`
      );
    }
    if (panelRef.current === "bots") {
      closePanel();
    }
    return {
      botId: createdBotId,
      importedName,
      importedBotHash,
      restoredMemories: restored,
    };
  }

  function parseBotGroupManifest(raw: string): BotGroupManifestV1 | null {
    try {
      const parsedUnknown = JSON.parse(raw) as unknown;
      if (!parsedUnknown || typeof parsedUnknown !== "object" || Array.isArray(parsedUnknown)) {
        return null;
      }
      const manifest = parsedUnknown as Partial<BotGroupManifestV1>;
      if (manifest.schema !== "prism-bot-group-manifest-v1") return null;
      return manifest as BotGroupManifestV1;
    } catch {
      return null;
    }
  }

  async function importBotZipBundle(file: File): Promise<void> {
    setPanelError(null);
    setPanelNotice(null);
    const archiveBytes = new Uint8Array(await file.arrayBuffer());
    let entries: Record<string, Uint8Array>;
    try {
      entries = unzipSync(archiveBytes);
    } catch {
      throw new Error("Could not read ZIP archive.");
    }
    const allEntries = Object.entries(entries);
    const botEntries = allEntries.filter(([name]) => name.trim().toLowerCase().endsWith(".bot"));
    if (botEntries.length === 0) {
      throw new Error("ZIP contains no .bot files.");
    }
    const manifestEntry = allEntries.find(
      ([name]) => name.trim().toLowerCase().endsWith("manifest.json")
    );
    const manifest = manifestEntry
      ? parseBotGroupManifest(strFromU8(manifestEntry[1]))
      : null;
    const botIdByHash = new Map<string, string>();
    for (const bot of bots) {
      const hash = normalizeImportedBotHash(bot.export_hash);
      if (hash) botIdByHash.set(hash, bot.id);
    }
    const importedBotIds: string[] = [];
    const importedBotIdByEntryName = new Map<string, string>();
    let importedCount = 0;
    let overwrittenCount = 0;
    let skippedCount = 0;
    let failedCount = 0;
    let restoredTotal = 0;

    for (const [entryName, bytes] of botEntries) {
      const raw = strFromU8(bytes);
      try {
        const parsed = parseBotExportPayload(raw);
        const importedHash = normalizeImportedBotHash(parsed.botHash);
        let allowDuplicateHash = false;
        if (importedHash && botIdByHash.has(importedHash)) {
          const duplicateName =
            typeof parsed.bot?.name === "string" && parsed.bot.name.trim().length > 0
              ? parsed.bot.name.trim()
              : entryName;
          const shouldOverwrite = window.confirm(
            `${duplicateName} already exists. Click OK to overwrite, or Cancel to skip it.`
          );
          if (!shouldOverwrite) {
            skippedCount += 1;
            continue;
          }
          const existingId = botIdByHash.get(importedHash);
          if (existingId) {
            await api(`/api/bots/${encodeURIComponent(existingId)}`, { method: "DELETE" });
          }
          botIdByHash.delete(importedHash);
          allowDuplicateHash = true;
          overwrittenCount += 1;
        }
        const result = await importBotFromExportRawText(raw, {
          allowDuplicateHash,
          suppressNotice: true,
          suppressPanelReset: true,
          selectInChat: false,
        });
        importedCount += 1;
        restoredTotal += result.restoredMemories;
        importedBotIds.push(result.botId);
        importedBotIdByEntryName.set(entryName.trim().toLowerCase(), result.botId);
        if (result.importedBotHash) {
          botIdByHash.set(result.importedBotHash, result.botId);
        }
      } catch {
        failedCount += 1;
      }
    }

    if (manifest?.group?.name && importedBotIds.length > 0) {
      const manifestName = manifest.group.name.trim();
      const manifestDescription =
        typeof manifest.group.description === "string" ? manifest.group.description.trim() : "";
      const manifestBotIds =
        Array.isArray(manifest.group.botFileNames) && manifest.group.botFileNames.length > 0
          ? manifest.group.botFileNames
              .map((name) => importedBotIdByEntryName.get(String(name).trim().toLowerCase()) ?? null)
              .filter((id): id is string => Boolean(id))
          : [];
      const targetBotIds = manifestBotIds.length > 0 ? manifestBotIds : importedBotIds;
      setBotLibraryGroups((current) => {
        const normalized = normalizeBotLibraryGroups(current);
        const existingIndex = normalized.findIndex(
          (group) => group.name.trim().toLowerCase() === manifestName.toLowerCase()
        );
        if (existingIndex >= 0) {
          const existing = normalized[existingIndex];
          const next = [...normalized];
          next[existingIndex] = {
            ...existing,
            description: manifestDescription || existing.description,
            botIds: Array.from(new Set([...existing.botIds, ...targetBotIds])),
            updatedAt: new Date().toISOString(),
          };
          return normalizeBotLibraryGroups(next);
        }
        return normalizeBotLibraryGroups([
          ...normalized,
          {
            id:
              typeof crypto !== "undefined" && typeof crypto.randomUUID === "function"
                ? `group:${crypto.randomUUID()}`
                : `group:${Date.now().toString(36)}`,
            name: manifestName,
            description: manifestDescription,
            botIds: Array.from(new Set(targetBotIds)),
            builtIn: false,
            createdAt: new Date().toISOString(),
            updatedAt: new Date().toISOString(),
          },
        ]);
      });
    }

    if (importedCount === 0 && failedCount > 0) {
      throw new Error("ZIP import failed. None of the .bot files could be imported.");
    }
    const summaryParts = [
      `${importedCount} imported`,
      `${overwrittenCount} overwritten`,
      `${skippedCount} skipped`,
      `${failedCount} failed`,
    ];
    if (restoredTotal > 0) {
      summaryParts.push(`${restoredTotal} memories restored`);
    }
    setPanelNotice(`ZIP import complete: ${summaryParts.join(" · ")}.`);
    if (importedBotIds.length === 1) {
      selectImportedBotInChatMode(importedBotIds[0]!);
    }
  }

  async function handleBotImportFileSelection(
    event: React.ChangeEvent<HTMLInputElement>
  ): Promise<void> {
    const file = event.currentTarget.files?.[0];
    event.currentTarget.value = "";
    if (!file) return;
    const lower = file.name.trim().toLowerCase();
    const isBotFile = lower.endsWith(".bot");
    const isZipFile = lower.endsWith(".zip");
    if (!isBotFile && !isZipFile) {
      setPanelError("Only .bot files can be imported from disk.");
      return;
    }
    setImportBotFileBusy(true);
    setImportBotFileBusyName(file.name);
    setImportBotFileBusyColor(null);
    setImportBotFileBusyGlyph(DEFAULT_BOT_GLYPH);
    try {
      if (isZipFile) {
        setImportBotFileBusyName(file.name);
        await importBotZipBundle(file);
      } else {
        const raw = await file.text();
        const hint = parseImportBotLoadingHint(raw);
        if (hint.name) setImportBotFileBusyName(hint.name);
        setImportBotFileBusyColor(hint.color);
        setImportBotFileBusyGlyph(hint.glyph);
        await importBotFromExportRawText(raw);
      }
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Bot import failed.");
    } finally {
      setImportBotFileBusy(false);
      setImportBotFileBusyName("");
      setImportBotFileBusyColor(null);
      setImportBotFileBusyGlyph(DEFAULT_BOT_GLYPH);
    }
  }

  function openImportBotModal(): void {
    setPanelError(null);
    setImportBotPasteError(null);
    setImportBotPasteText("");
    setImportBotPasteBusy(false);
    if (!devToolsBotImportPasteEnabled) {
      setImportBotModalPhase("closed");
      queueMicrotask(() => {
        botImportInputRef.current?.click();
      });
      return;
    }
    setImportBotModalPhase("choose");
  }

  function handleImportBotChooseUpload(): void {
    closeImportBotModal();
    queueMicrotask(() => {
      botImportInputRef.current?.click();
    });
  }

  async function handleConfirmImportBotPaste(): Promise<void> {
    setImportBotPasteError(null);
    setImportBotPasteBusy(true);
    try {
      await importBotFromExportRawText(importBotPasteText);
      closeImportBotModal();
    } catch (err) {
      setImportBotPasteError(err instanceof Error ? err.message : "Bot import failed.");
    } finally {
      setImportBotPasteBusy(false);
    }
  }

  const updateCanvasBotMarqueeSelection = useCallback((
    drag: CanvasBotMarqueeDragState,
    clientX: number,
    clientY: number
  ) => {
    const frameRect = drag.frameRect;
    const clampedStartX = Math.max(frameRect.left, Math.min(frameRect.right, drag.startClientX));
    const clampedStartY = Math.max(frameRect.top, Math.min(frameRect.bottom, drag.startClientY));
    const clampedCurrentX = Math.max(frameRect.left, Math.min(frameRect.right, clientX));
    const clampedCurrentY = Math.max(frameRect.top, Math.min(frameRect.bottom, clientY));
    const left = Math.min(clampedStartX, clampedCurrentX);
    const top = Math.min(clampedStartY, clampedCurrentY);
    const right = Math.max(clampedStartX, clampedCurrentX);
    const bottom = Math.max(clampedStartY, clampedCurrentY);
    const viewportRect = { left, top, right, bottom };
    setCanvasBotMarqueeRect({
      left: left - frameRect.left,
      top: top - frameRect.top,
      width: right - left,
      height: bottom - top,
    });
    const nextSelectedIds = new Set<string>();
    for (const { botId, rect } of drag.tileRects) {
      if (rectsIntersect(viewportRect, rect)) nextSelectedIds.add(botId);
    }
    setCanvasSelectedBotIds((current) =>
      stringSetsEqual(current, nextSelectedIds) ? current : nextSelectedIds
    );
  }, []);

  const handleCanvasBotMarqueePointerDown = useCallback((
    event: React.PointerEvent<HTMLDivElement>
  ): boolean => {
    if (detail || pendingReplyVisible) return false;
    if (event.pointerType === "touch") return false;
    if (event.button !== 0) return false;
    const target = event.target;
    if (
      target instanceof Element &&
      target.closest("button, input, textarea, select, a, [role='button'], [data-bot-id]")
    ) {
      return false;
    }
    const frame = event.currentTarget;
    const frameRect = frame.getBoundingClientRect();
    if (frameRect.width <= 0 || frameRect.height <= 0) return false;
    const tileRects = Array.from(frame.querySelectorAll<HTMLElement>("[data-bot-id]"))
      .map((node) => {
        const botId = node.dataset.botId;
        if (!botId) return null;
        return { botId, rect: node.getBoundingClientRect() };
      })
      .filter((entry): entry is { botId: string; rect: DOMRect } => Boolean(entry));
    if (tileRects.length === 0) return false;
    canvasBotMarqueeDragRef.current = {
      pointerId: event.pointerId,
      frame,
      frameRect,
      startClientX: event.clientX,
      startClientY: event.clientY,
      active: false,
      tileRects,
    };
    setCanvasBotMarqueeRect(null);
    try {
      frame.setPointerCapture(event.pointerId);
    } catch {
      // Some browser/test environments do not expose pointer capture.
    }
    return true;
  }, [detail, pendingReplyVisible]);

  const handleCanvasBotMarqueePointerMove = useCallback((
    event: React.PointerEvent<HTMLDivElement>
  ): boolean => {
    const drag = canvasBotMarqueeDragRef.current;
    if (!drag || drag.pointerId !== event.pointerId) return false;
    const dx = event.clientX - drag.startClientX;
    const dy = event.clientY - drag.startClientY;
    if (!drag.active) {
      if (Math.hypot(dx, dy) < BOT_MARQUEE_DRAG_THRESHOLD_PX) return true;
      drag.active = true;
    }
    event.preventDefault();
    updateCanvasBotMarqueeSelection(drag, event.clientX, event.clientY);
    return true;
  }, [updateCanvasBotMarqueeSelection]);

  const handleCanvasBotMarqueePointerEnd = useCallback((
    event: React.PointerEvent<HTMLDivElement>
  ): boolean => {
    const drag = canvasBotMarqueeDragRef.current;
    if (!drag || drag.pointerId !== event.pointerId) return false;
    const wasActive = drag.active;
    if (wasActive) {
      updateCanvasBotMarqueeSelection(drag, event.clientX, event.clientY);
      canvasBotMarqueeSuppressClickRef.current = true;
      window.setTimeout(() => {
        canvasBotMarqueeSuppressClickRef.current = false;
      }, 0);
      event.preventDefault();
      event.stopPropagation();
    } else {
      setCanvasSelectedBotIds((current) => (current.size === 0 ? current : new Set()));
    }
    setCanvasBotMarqueeRect(null);
    canvasBotMarqueeDragRef.current = null;
    try {
      if (drag.frame.hasPointerCapture(event.pointerId)) {
        drag.frame.releasePointerCapture(event.pointerId);
      }
    } catch {
      // Non-fatal: capture may already be released.
    }
    return true;
  }, [updateCanvasBotMarqueeSelection]);

  const resetEmptyStateBotSelection = useCallback(() => {
    cancelPendingEmptyStateSearchOpen();
    setSelectedBotId(null);
    setSandboxGridSelectedBotId(null);
    setCanvasBotMarqueeRect(null);
    canvasBotMarqueeDragRef.current = null;
    setCanvasSelectedBotIds((current) => (current.size === 0 ? current : new Set()));
  }, [cancelPendingEmptyStateSearchOpen]);

  const handleEmptyStateBackgroundClick = useCallback((event: React.MouseEvent<HTMLDivElement>) => {
    if (canvasBotMarqueeSuppressClickRef.current) {
      canvasBotMarqueeSuppressClickRef.current = false;
      event.preventDefault();
      event.stopPropagation();
      return;
    }
    if (detail || pendingIncognito) return;
    const target = event.target;
    if (!(target instanceof Element)) return;
    const interactiveTarget = target.closest(
      "button, input, textarea, select, a, [role='button'], [data-starter-bot-affordance='true'], [data-bot-picker-frame='true']"
    );
    if (interactiveTarget) return;
    setCanvasSelectedBotIds((current) => (current.size === 0 ? current : new Set()));
  }, [
    detail,
    pendingIncognito,
  ]);

  const openEmptyStateBotSearch = useCallback(() => {
    cancelPendingEmptyStateSearchOpen();
    setSelectedBotId(null);
    setSandboxGridSelectedBotId(null);
    if (botPickerReturnEndAtRef.current > Date.now()) return;
    if (emptyStateSearchActive) {
      setEmptyStateSearchOpen(false);
      setEmptyStateBotNameFilter("");
      return;
    }
    if (hueFilterCenter !== null) {
      setEmptyStateSearchOpen(false);
      setEmptyStateBotNameFilter("");
      startBotPickerReturnToAll();
      return;
    }
    setHueFilterCenter(null);
    setEmptyStateSearchOpen(true);
  }, [
    cancelPendingEmptyStateSearchOpen,
    emptyStateSearchActive,
    hueFilterCenter,
    startBotPickerReturnToAll,
  ]);

  const closeEmptyStateBotSearch = useCallback(() => {
    cancelPendingEmptyStateSearchOpen();
    setEmptyStateSearchOpen(false);
    setEmptyStateBotNameFilter("");
    spotlightTypingArmedRef.current = false;
  }, [cancelPendingEmptyStateSearchOpen]);

  function resetEmptyStateToPrismHome(): void {
    closeEmptyStateBotSearch();
    resetEmptyStateBotSelection();
    setPendingIncognito(false);
    if (hueFilterCenter !== null) {
      startBotPickerReturnToAll();
    } else {
      setHueFilterCenter(null);
    }
  }

  const focusDraftInput = useCallback(() => {
    window.setTimeout(() => {
      draftComposerRef.current?.focus({ preventScroll: true });
    }, 0);
  }, []);

  const closeEmptyStateBotSearchAndFocusDraft = useCallback(() => {
    closeEmptyStateBotSearch();
    focusDraftInput();
  }, [closeEmptyStateBotSearch, focusDraftInput]);

  const commitEmptyStateBotSelection = useCallback((botId: string) => {
    canvasBotMarqueeDragRef.current = null;
    setCanvasBotMarqueeRect(null);
    setCanvasSelectedBotIds((current) => (current.size === 0 ? current : new Set()));
    if (selectedBotId === botId) {
      setSandboxGridSelectedBotId(botId);
      focusDraftInput();
      return;
    }
    cancelPendingEmptyStateSearchOpen();
    setCanvasBotSwitchOverlayPhase("enter");
    canvasBotSwitchTransitionStartedAtRef.current = Date.now();
    pendingCanvasBotUnfoldRef.current = true;
    setCanvasBotSwitchTransitioning(true);
    // Committing a bot exits visible lens mode, but keeps the current
    // filtered/zoomed bot view intact. `emptyStateLensVisible` hides the
    // slider while `shellStyle` lets the selected bot own the interface
    // color, so the hue lens no longer competes with the bot accent.
    setSelectedBotId(botId);
    setSandboxGridSelectedBotId(botId);
    setEmptyStateSearchOpen(false);
    setEmptyStateBotNameFilter("");
    spotlightTypingArmedRef.current = false;
    focusDraftInput();
  }, [cancelPendingEmptyStateSearchOpen, focusDraftInput, selectedBotId]);

  useEffect(() => {
    if (view !== "chat") return;
    const botId = pendingImportedChatBotSelectionRef.current;
    if (!botId) return;
    pendingImportedChatBotSelectionRef.current = null;
    commitEmptyStateBotSelection(botId);
  }, [commitEmptyStateBotSelection, view]);

  function selectImportedBotInChatMode(botId: string): void {
    pendingImportedChatBotSelectionRef.current = null;
    if (view !== "chat") {
      pendingImportedChatBotSelectionRef.current = botId;
      navigateToView("chat");
      return;
    }
    setConversationStarterPrompts(null);
    setChatStartupSummary(DEFAULT_CHAT_STARTUP_SUMMARY);
    chatSummaryRefreshMarkerRef.current = null;
    setSelectedId(null);
    setDetail(null);
    setChatBotOverride(undefined);
    setSidebarOpen(false);
    commitEmptyStateBotSelection(botId);
  }

  const openEmptyStateBotSearchFromTyping = useCallback((typedCharacter: string) => {
    cancelPendingEmptyStateSearchOpen();
    setSelectedBotId(null);
    setSandboxGridSelectedBotId(null);
    setEmptyStateBotNameFilter((current) =>
      current.length > 0 ? `${current}${typedCharacter}` : typedCharacter
    );
    if (hueFilterCenter !== null) {
      setEmptyStateSearchOpen(false);
      startBotPickerReturnToAll();
      showEmptyStateSearchAfterReturn();
      return;
    }
    setHueFilterCenter(null);
    showEmptyStateSearchAfterReturn();
  }, [
    cancelPendingEmptyStateSearchOpen,
    hueFilterCenter,
    showEmptyStateSearchAfterReturn,
    startBotPickerReturnToAll,
  ]);

  const handleComposerBotSelectionChange = useCallback(
    (next: string) => {
      const nextBotId = next || null;
      setSelectedBotId(nextBotId);
      // In Sandbox, hero + tile highlighting are keyed off the canvas focus
      // state. Keep it in sync when selection comes from the header dropdown.
      if (view === "sandbox") {
        setSandboxGridSelectedBotId(nextBotId);
      }
    },
    [view]
  );

  useEffect(() => {
    if (!emptyStateTypingSearchAvailable) return;
    function handlePageTyping(event: KeyboardEvent) {
      if (event.defaultPrevented || event.metaKey || event.ctrlKey || event.altKey) return;
      const activeElement = document.activeElement;
      if (event.key === "Tab") {
        if (!emptyStateSearchActive && !spotlightTypingArmedRef.current) return;
        if (
          activeElement instanceof Element &&
          activeElement.closest(
            "[data-starter-compose-surface='true'],[data-prism-compose-field='true']"
          )
        ) {
          return;
        }
        const spotlightInput = emptyStateSearchInputRef.current;
        const focusSpotlight = () => {
          if (hueFilterCenter !== null) {
            setEmptyStateSearchOpen(false);
            startBotPickerReturnToAll();
            focusEmptyStateSearchAfterReturn();
            return;
          }
          setHueFilterCenter(null);
          setEmptyStateSearchOpen(true);
          window.setTimeout(() => {
            spotlightInput?.focus({ preventScroll: true });
          }, 0);
        };

        event.preventDefault();
        if (!emptyStateSearchActive) {
          focusSpotlight();
          return;
        }
        if (activeElement === spotlightInput) {
          closeEmptyStateBotSearchAndFocusDraft();
          return;
        }
        spotlightInput?.focus({ preventScroll: true });
        return;
      }
      const activeElementIsEditable =
        activeElement instanceof HTMLElement &&
        (
          activeElement.isContentEditable ||
          activeElement instanceof HTMLInputElement ||
          activeElement instanceof HTMLTextAreaElement ||
          activeElement instanceof HTMLSelectElement
        );
      if (activeElementIsEditable) return;
      const pageHasFocus =
        !activeElement ||
        activeElement === document.body ||
        activeElement === document.documentElement;
      const spotlightHasFocusFallback = emptyStateSearchActive || pageHasFocus;
      if (!spotlightHasFocusFallback) return;

      if (event.key === "Backspace" && emptyStateSearchActive) {
        event.preventDefault();
        setEmptyStateBotNameFilter((current) => {
          if (current.length <= 1) {
            window.setTimeout(closeEmptyStateBotSearchAndFocusDraft, 0);
            return "";
          }
          return current.slice(0, -1);
        });
        return;
      }
      if (event.key === "Escape" && emptyStateSearchActive) {
        event.preventDefault();
        closeEmptyStateBotSearch();
        return;
      }
      if (event.key.length !== 1 || event.key.trim().length === 0) return;
      if (!emptyStateSearchActive && !spotlightTypingArmedRef.current) return;
      if (!emptyStateSearchActive && !pageHasFocus) return;
      event.preventDefault();
      openEmptyStateBotSearchFromTyping(event.key);
    }
    window.addEventListener("keydown", handlePageTyping);
    return () => window.removeEventListener("keydown", handlePageTyping);
  }, [
    closeEmptyStateBotSearchAndFocusDraft,
    closeEmptyStateBotSearch,
    emptyStateSearchActive,
    emptyStateTypingSearchAvailable,
    focusEmptyStateSearchAfterReturn,
    hueFilterCenter,
    openEmptyStateBotSearchFromTyping,
    startBotPickerReturnToAll,
  ]);

  useEffect(() => {
    if (!emptyStateSearchActive) return;
    function handleDocumentClick(event: MouseEvent) {
      const target = event.target;
      if (!(target instanceof Node)) return;
      if (emptyStateSearchRef.current?.contains(target)) return;
      closeEmptyStateBotSearch();
    }
    document.addEventListener("click", handleDocumentClick);
    return () => document.removeEventListener("click", handleDocumentClick);
  }, [closeEmptyStateBotSearch, emptyStateSearchActive]);

  const relocateHueLensToBot = useCallback(
    (botId: string, geom: PickerGeometry): boolean => {
      if (emptyStateSearchActive || hueFilterCenter !== null) return false;
      if (!pickerUsesHueNavigation(geom, viewportWidth)) return false;
      const bot = pickerSourceBots.find((candidate) => candidate.id === botId);
      if (!bot || !botHasFilterableColor(bot)) return false;
      const { h } = hexToHsl(bot.color!.trim());
      setHueFilterCenter(hueLensPositionForHue(h));
      setSelectedBotId(null);
      return true;
    },
    [emptyStateSearchActive, hueFilterCenter, pickerSourceBots, viewportWidth]
  );

  // Touch keyboard-balloon handlers. Shared by both the Chat-mode and
  // Sandbox-mode empty-state picker frames. Active only when the gesture
  // is genuine touch input AND the picker is in hue-navigation territory:
  // Stage 3+ on mobile, Stage 4+ elsewhere. The first tap zooms/snaps the
  // hue lens; once narrowed, taps select individual bots again.
  const handleTouchPickerDown = useCallback(
    (event: React.PointerEvent<HTMLDivElement>, geom: PickerGeometry) => {
      if (event.pointerType !== "touch") return;
      if (!pickerUsesHueNavigation(geom, viewportWidth)) return;
      // Capture so subsequent move/up events route here even if the
      // finger drifts off this element. Without capture, the user's
      // finger crossing into a child tile would lose the gesture.
      event.currentTarget.setPointerCapture(event.pointerId);
      touchPreviewPointerIdRef.current = event.pointerId;
    },
    [viewportWidth]
  );

  const handleTouchPickerMove = useCallback(
    (event: React.PointerEvent<HTMLDivElement>) => {
      if (event.pointerId !== touchPreviewPointerIdRef.current) return;
      cancelBotContextLongPress(event.pointerId);
    },
    [cancelBotContextLongPress]
  );

  const handleTouchPickerUp = useCallback(
    (event: React.PointerEvent<HTMLDivElement>, geom: PickerGeometry) => {
      if (event.pointerId !== touchPreviewPointerIdRef.current) return;
      cancelBotContextLongPress(event.pointerId);
      if (botContextSuppressClickRef.current) {
        event.preventDefault();
        setTouchPreview(null);
        touchPreviewPointerIdRef.current = null;
        if (event.currentTarget.hasPointerCapture(event.pointerId)) {
          event.currentTarget.releasePointerCapture(event.pointerId);
        }
        window.setTimeout(() => {
          botContextSuppressClickRef.current = false;
        }, 150);
        return;
      }
      const botId = findBotIdAtPoint(event.clientX, event.clientY);
      if (botId) {
        const relocated = relocateHueLensToBot(botId, geom);
        if (!relocated) {
          commitEmptyStateBotSelection(botId);
        }
      }
      setTouchPreview(null);
      touchPreviewPointerIdRef.current = null;
      if (event.currentTarget.hasPointerCapture(event.pointerId)) {
        event.currentTarget.releasePointerCapture(event.pointerId);
      }
    },
    [cancelBotContextLongPress, commitEmptyStateBotSelection, relocateHueLensToBot]
  );

  const handleTouchPickerCancel = useCallback(
    (event: React.PointerEvent<HTMLDivElement>) => {
      if (event.pointerId !== touchPreviewPointerIdRef.current) return;
      cancelBotContextLongPress(event.pointerId);
      setTouchPreview(null);
      touchPreviewPointerIdRef.current = null;
      if (event.currentTarget.hasPointerCapture(event.pointerId)) {
        event.currentTarget.releasePointerCapture(event.pointerId);
      }
    },
    [cancelBotContextLongPress]
  );

  const renderEmptyStateBotSearch = (): React.JSX.Element | null => {
    if (!emptyStateSearchActive || pickerSourceBots.length === 0) return null;
    const resultLabel =
      normalizedEmptyStateBotNameFilter.length === 0
        ? "Start typing to filter bots by name."
        : filteredBots.length === 1
          ? "1 bot found"
          : `${filteredBots.length} bots found`;
    return (
      <div
        ref={emptyStateSearchRef}
        className={styles.emptyStateSearch}
        role="search"
        onBlur={(event) => {
          const nextFocus = event.relatedTarget;
          if (nextFocus instanceof Node && event.currentTarget.contains(nextFocus)) return;
          closeEmptyStateBotSearch();
        }}
      >
        <div className={styles.emptyStateSearchField}>
          <span className={styles.emptyStateSearchGlyph} aria-hidden="true">
            ⌕
          </span>
          <input
            ref={emptyStateSearchInputRef}
            type="search"
            value={emptyStateBotNameFilter}
            onChange={(event) => setEmptyStateBotNameFilter(event.currentTarget.value)}
            onKeyDown={(event) => {
              if (event.key === "Escape") {
                event.preventDefault();
                closeEmptyStateBotSearch();
                return;
              }
              if (event.key === "Backspace" && emptyStateBotNameFilter.length <= 1) {
                event.preventDefault();
                closeEmptyStateBotSearchAndFocusDraft();
              }
            }}
            className={styles.emptyStateSearchInput}
            placeholder="Search bots"
            aria-label="Search bots by name"
          />
        </div>
        <div className={styles.emptyStateSearchMeta} aria-live="polite">
          {resultLabel}
        </div>
      </div>
    );
  };

  const disarmDelete = useCallback(() => {
    if (pendingDeleteTimerRef.current) {
      clearTimeout(pendingDeleteTimerRef.current);
      pendingDeleteTimerRef.current = null;
    }
    setPendingDeleteKey(null);
  }, []);

  const beginConversationGroupPointerDrag = useCallback((
    event: React.PointerEvent<HTMLElement>,
    groupKey: string
  ) => {
    if (event.button !== 0) return;
    if (conversationGroupPointerDragRef.current || draggingConversationGroupKey) return;
    conversationGroupPointerDragRef.current = {
      key: groupKey,
      pointerId: event.pointerId,
      startY: event.clientY,
      active: false,
    };
    try {
      event.currentTarget.setPointerCapture(event.pointerId);
    } catch {
      // Pointer capture is unavailable in some browser/test environments.
    }
  }, [draggingConversationGroupKey]);

  const updateConversationGroupPointerDrag = useCallback((
    event: React.PointerEvent<HTMLElement>
  ) => {
    const drag = conversationGroupPointerDragRef.current;
    if (!drag || drag.pointerId !== event.pointerId) return;
    const deltaY = event.clientY - drag.startY;
    if (!drag.active) {
      if (Math.abs(deltaY) < 6) return;
      drag.active = true;
      disarmDelete();
      setExpandedConversationGroupKey((previous) =>
        previous === drag.key ? null : previous
      );
      setDraggingConversationGroupKey(drag.key);
      suppressConversationGroupClickRef.current = true;
    }

    event.preventDefault();
    const hoveredGroup = document
      .elementsFromPoint(event.clientX, event.clientY)
      .map((element) =>
        element instanceof HTMLElement
          ? element.closest<HTMLElement>("[data-conversation-group-key]")
          : null
      )
      .find((element) => element && element.dataset.conversationGroupKey !== drag.key);
    const targetKey = hoveredGroup?.dataset.conversationGroupKey;
    if (!hoveredGroup || !targetKey) return;
    const rect = hoveredGroup.getBoundingClientRect();
    const position: ConversationGroupDropPosition =
      event.clientY > rect.top + rect.height / 2 ? "after" : "before";
    moveConversationGroup(drag.key, targetKey, position);
  }, [disarmDelete, moveConversationGroup]);

  const endConversationGroupPointerDrag = useCallback((
    event: React.PointerEvent<HTMLElement>
  ) => {
    const drag = conversationGroupPointerDragRef.current;
    if (!drag || drag.pointerId !== event.pointerId) return;
    const wasActive = drag.active;
    try {
      event.currentTarget.releasePointerCapture(event.pointerId);
    } catch {
      // Non-fatal: capture may already be released.
    }
    clearConversationGroupDragState();
    if (wasActive) {
      event.preventDefault();
      window.setTimeout(() => {
        suppressConversationGroupClickRef.current = false;
      }, 0);
    }
  }, [clearConversationGroupDragState]);

  useEffect(() => {
    if (!draggingConversationGroupKey) return;
    const handleViewportLeave = (event: MouseEvent) => {
      if (event.relatedTarget !== null) return;
      abortConversationGroupPointerDrag();
    };
    const handleWindowBlur = () => {
      abortConversationGroupPointerDrag();
    };
    document.documentElement.addEventListener("mouseleave", handleViewportLeave);
    window.addEventListener("blur", handleWindowBlur);
    return () => {
      document.documentElement.removeEventListener("mouseleave", handleViewportLeave);
      window.removeEventListener("blur", handleWindowBlur);
    };
  }, [abortConversationGroupPointerDrag, draggingConversationGroupKey]);

  const armDelete = useCallback((key: string) => {
    if (pendingDeleteTimerRef.current) {
      clearTimeout(pendingDeleteTimerRef.current);
      pendingDeleteTimerRef.current = null;
    }
    setPendingDeleteKey(key);
    // DELETE_ALL_KEY / DELETE_ALL_BOTS_KEY are special: their confirm
    // surface is a centered modal, and the 3.5 s window that makes the
    // inline "Are you sure?" pill feel snappy would instead pull the
    // modal out from under the user mid-read. We skip auto-disarm for
    // them and rely on Cancel / backdrop / Esc to dismiss explicitly.
    if (
      key === DELETE_ALL_KEY ||
      key === DELETE_ALL_COFFEE_SESSIONS_KEY ||
      key === DELETE_ALL_BOTS_KEY ||
      key.startsWith(DELETE_COFFEE_GROUP_KEY_PREFIX)
    ) return;
    pendingDeleteTimerRef.current = setTimeout(() => {
      setPendingDeleteKey(null);
      pendingDeleteTimerRef.current = null;
    }, DELETE_CONFIRM_WINDOW_MS);
  }, []);

  // Clean up the pending-delete timer on unmount so an in-flight auto-disarm
  // doesn't call setState on a torn-down component.
  useEffect(() => () => {
    if (pendingDeleteTimerRef.current) {
      clearTimeout(pendingDeleteTimerRef.current);
    }
  }, []);

  // Right-click is suppressed app-wide for custom surfaces, but text-entry
  // controls should keep native OS context menus (copy/paste/spellcheck).
  // This preserves expected platform behavior in all textarea/input fields.
  const shouldAllowNativeContextMenu = useCallback((target: EventTarget | null): boolean => {
    if (!(target instanceof HTMLElement)) return false;
    return target.closest(
      [
        "textarea",
        "input:not([type='button']):not([type='submit']):not([type='reset'])",
        "[contenteditable='true']",
        "[contenteditable='']",
        "[role='textbox']",
      ].join(", ")
    ) !== null;
  }, []);

  const handleAppContextMenu = useCallback((event: React.MouseEvent<HTMLElement>) => {
    if (shouldAllowNativeContextMenu(event.target)) return;
    event.preventDefault();
  }, [shouldAllowNativeContextMenu]);

  /**
   * Right-click anywhere in the Coffee shell that isn't a seat / a button / a
   * field surfaces the same actions the Coffee header icons offer, in their
   * text-equivalent form. Mirrors `renderCanvasToolsContextMenu` for Chat.
   */
  const handleCoffeeShellContextMenu = useCallback(
    (event: React.MouseEvent<HTMLElement>) => {
      if (shouldAllowNativeContextMenu(event.target)) return;
      event.preventDefault();
      if (event.target instanceof HTMLElement) {
        // Defer to the seat-specific handler if the click landed on a Coffee seat.
        if (event.target.closest('[data-coffee-seat-context="true"]')) return;
      }
      const clamped = clampContextMenuPosition(
        event.clientX,
        event.clientY,
        CANVAS_TOOLS_CONTEXT_MENU_ESTIMATED_WIDTH_PX,
        CANVAS_TOOLS_CONTEXT_MENU_ESTIMATED_HEIGHT_PX
      );
      setCoffeeShellContextMenu({ x: clamped.x, y: clamped.y });
      setCoffeeBotContextMenu(null);
      setCanvasToolsContextMenu(null);
      setBotContextMenu(null);
      setConversationGroupContextMenu(null);
    },
    [shouldAllowNativeContextMenu]
  );

  /**
   * Right-click on a seated bot — text shortcuts to that bot's customizer + memories.
   */
  const openCoffeeBotContextMenu = useCallback(
    (botId: string, x: number, y: number) => {
      const clamped = clampContextMenuPosition(
        x,
        y,
        BOT_CONTEXT_MENU_ESTIMATED_WIDTH_PX,
        BOT_CONTEXT_MENU_ESTIMATED_HEIGHT_PX
      );
      setCoffeeBotContextMenu({ botId, x: clamped.x, y: clamped.y });
      setCoffeeShellContextMenu(null);
      setBotContextMenu(null);
      setCanvasToolsContextMenu(null);
      setConversationGroupContextMenu(null);
    },
    []
  );

  const handleStoryShellContextMenu = useCallback(
    (event: React.MouseEvent<HTMLElement>) => {
      event.preventDefault();
      const clamped = clampContextMenuPosition(
        event.clientX,
        event.clientY,
        CANVAS_TOOLS_CONTEXT_MENU_ESTIMATED_WIDTH_PX,
        260
      );
      setStoryShellContextMenu({ x: clamped.x, y: clamped.y });
      setCoffeeShellContextMenu(null);
      setCoffeeBotContextMenu(null);
      setCanvasToolsContextMenu(null);
      setBotContextMenu(null);
      setConversationGroupContextMenu(null);
    },
    []
  );

  const handleMessagesFrameContextMenu = useCallback(
    (event: React.MouseEvent<HTMLElement>) => {
      if (shouldAllowNativeContextMenu(event.target)) return;
      event.preventDefault();
      event.stopPropagation();
      const clamped = clampContextMenuPosition(
        event.clientX,
        event.clientY,
        CANVAS_TOOLS_CONTEXT_MENU_ESTIMATED_WIDTH_PX,
        CANVAS_TOOLS_CONTEXT_MENU_ESTIMATED_HEIGHT_PX
      );
      setCanvasToolsContextMenu({ x: clamped.x, y: clamped.y });
      closeMessageContextOverlay();
      setBotContextMenu(null);
      setConversationGroupContextMenu(null);
      setChatOverflowMenuOpen(false);
    },
    [shouldAllowNativeContextMenu, closeMessageContextOverlay]
  );

  // ── Hold-to-delete-all gesture ────────────────────────────────────────
  // `startHoldDelete` / `cancelHoldDelete` are called from pointer events
  // on every chat-clear affordance (sidebar × rows + header Delete). The
  // discrete React state change (holdingKey set/cleared) drives the CSS
  // `[data-holding="true"]` attribute, which owns the actual 900 ms morph
  // animation — we never re-render on intermediate progress, so even a
  // long hold doesn't thrash React's reconciler.
  const cancelHoldDelete = useCallback(() => {
    if (holdTimerRef.current) {
      clearTimeout(holdTimerRef.current);
      holdTimerRef.current = null;
    }
    setHoldingKey(null);
  }, []);

  const startHoldDelete = useCallback((key: string) => {
    // Refuse to start a new hold while anything is already armed: the
    // active confirm pill / modal deserves the user's attention first,
    // and a second gesture layering on top would be disorienting.
    if (pendingDeleteKey) return;
    if (holdTimerRef.current) {
      clearTimeout(holdTimerRef.current);
    }
    holdCompletedRef.current = false;
    setHoldingKey(key);
    // Route to the bots sentinel when the holding key is a bot × so the
    // confirmation modal asks the right question and the bulk action
    // wipes the right dataset. Any non-bot key (sidebar chat ×, header
    // Delete) stays on the original DELETE_ALL_KEY path.
    const allKey = key.startsWith(BOT_DELETE_KEY_PREFIX)
      ? DELETE_ALL_BOTS_KEY
      : DELETE_ALL_KEY;
    holdTimerRef.current = setTimeout(() => {
      // Threshold crossed — snap out of "holding" visuals and into the
      // armed-all state. The list-level data attribute flip takes the
      // ×'s from tilted-and-glowing straight into iOS jiggle, and
      // `armDelete` renders the confirmation modal.
      holdCompletedRef.current = true;
      setHoldingKey(null);
      holdTimerRef.current = null;
      armDelete(allKey);
    }, DELETE_ALL_HOLD_MS);
  }, [armDelete, pendingDeleteKey]);

  // Clean up the hold timer on unmount.
  useEffect(() => () => {
    if (holdTimerRef.current) {
      clearTimeout(holdTimerRef.current);
    }
  }, []);

  // Armed-all modal a11y: when the modal mounts, capture whatever had
  // focus (usually the × / header Delete the user was holding) so we can
  // restore focus to it on dismiss. While the modal is open, Escape
  // cancels — keeping the keyboard escape hatch consistent with every
  // other confirm surface in the app. Both the chat-scoped and bot-scoped
  // armed-all states share this contract so the two modals behave
  // identically from the keyboard / screen-reader side.
  const pendingCoffeeGroupDeleteIdForModal = parseCoffeeGroupDeleteKey(pendingDeleteKey);
  const isDeleteAllActive =
    pendingDeleteKey === DELETE_ALL_KEY ||
    pendingDeleteKey === DELETE_ALL_COFFEE_SESSIONS_KEY ||
    pendingDeleteKey === DELETE_ALL_BOTS_KEY ||
    pendingCoffeeGroupDeleteIdForModal !== null;
  useEffect(() => {
    if (!isDeleteAllActive) {
      // On close, return focus to the element that opened the modal
      // (if it still exists in the DOM and is focusable).
      const prev = preModalFocusRef.current;
      preModalFocusRef.current = null;
      if (prev && typeof prev.focus === "function" && document.contains(prev)) {
        // Use a microtask so React has flushed the modal-removal render
        // before we refocus — otherwise the browser may steal focus
        // back to <body> between our call and the reconciliation tick.
        queueMicrotask(() => {
          try { prev.focus({ preventScroll: true }); } catch { /* focus can fail on detached nodes */ }
        });
      }
      return;
    }
    // Modal is opening — remember where focus came from.
    const active = document.activeElement;
    preModalFocusRef.current =
      active instanceof HTMLElement ? active : null;

    function handleKey(event: KeyboardEvent) {
      if (event.key === "Escape") {
        event.stopPropagation();
        disarmDelete();
      }
    }
    document.addEventListener("keydown", handleKey);
    return () => document.removeEventListener("keydown", handleKey);
  }, [isDeleteAllActive, disarmDelete]);

  useEffect(() => {
    const id = parseCoffeeGroupDeleteKey(pendingDeleteKey);
    if (!id) return;
    if (!coffeeGroups.some((group) => group.id === id)) {
      disarmDelete();
    }
  }, [pendingDeleteKey, coffeeGroups, disarmDelete]);

  // Single-bot delete from the Bots panel header uses its own modal; if any
  // sidebar/header delete affordance arms, drop the header modal so only one
  // confirm surface is active.
  useEffect(() => {
    if (!pendingDeleteKey) return;
    setPanelBotDeleteConfirm(null);
    setSelectedBotDeleteConfirm(null);
  }, [pendingDeleteKey]);

  const isPanelBotDeleteModalOpen = panelBotDeleteConfirm !== null;
  useEffect(() => {
    if (!isPanelBotDeleteModalOpen) {
      const prev = prePanelBotDeleteModalFocusRef.current;
      prePanelBotDeleteModalFocusRef.current = null;
      if (prev && typeof prev.focus === "function" && document.contains(prev)) {
        queueMicrotask(() => {
          try { prev.focus({ preventScroll: true }); } catch { /* ignore */ }
        });
      }
      return;
    }
    const active = document.activeElement;
    prePanelBotDeleteModalFocusRef.current =
      active instanceof HTMLElement ? active : null;

    function handleKey(event: KeyboardEvent) {
      if (event.key === "Escape") {
        event.stopPropagation();
        setPanelBotDeleteConfirm(null);
      }
    }
    document.addEventListener("keydown", handleKey);
    return () => document.removeEventListener("keydown", handleKey);
  }, [isPanelBotDeleteModalOpen]);

  const isSweepConfirmModalOpen = sweepConfirmOpen;
  useEffect(() => {
    if (!isSweepConfirmModalOpen) {
      const prev = preSweepConfirmModalFocusRef.current;
      preSweepConfirmModalFocusRef.current = null;
      if (prev && typeof prev.focus === "function" && document.contains(prev)) {
        queueMicrotask(() => {
          try { prev.focus({ preventScroll: true }); } catch { /* ignore */ }
        });
      }
      return;
    }
    const active = document.activeElement;
    preSweepConfirmModalFocusRef.current =
      active instanceof HTMLElement ? active : null;

    function handleKey(event: KeyboardEvent) {
      if (event.key === "Escape") {
        event.stopPropagation();
        setSweepConfirmOpen(false);
      }
    }
    document.addEventListener("keydown", handleKey);
    return () => document.removeEventListener("keydown", handleKey);
  }, [isSweepConfirmModalOpen]);

  useEffect(() => {
    if (!sweepUndoToast) return;
    const remainingMs = Math.max(0, sweepUndoToast.expiresAt - Date.now());
    if (remainingMs <= 0) {
      setSweepUndoToast(null);
      return;
    }
    const timer = window.setTimeout(() => {
      setSweepUndoToast((current) =>
        current?.batchId === sweepUndoToast.batchId ? null : current
      );
    }, remainingMs);
    return () => window.clearTimeout(timer);
  }, [sweepUndoToast]);

  useEffect(() => {
    if (!devToolsOpen) return;
    function handleKey(event: KeyboardEvent) {
      if (event.key === "Escape") {
        event.stopPropagation();
        if (devTogglesOpen) {
          setDevTogglesOpen(false);
          return;
        }
        closeDevTools();
      }
    }
    document.addEventListener("keydown", handleKey);
    return () => document.removeEventListener("keydown", handleKey);
  }, [devToolsOpen, devTogglesOpen, closeDevTools]);

  // Clicking anywhere outside the delete / confirm affordance should disarm it.
  // This prevents the confirm pill from lingering in an awkward in-between
  // state after focus moves elsewhere in the sidebar.
  useEffect(() => {
    if (!pendingDeleteKey) {
      return;
    }

    function handlePointerDown(event: PointerEvent) {
      if (!isPrimaryPointerDismissal(event)) return;
      const target = event.target;
      // `Element` (not HTMLElement) is deliberate: clicks on inline SVG
      // glyphs have an SVGElement target, which is NOT an HTMLElement but
      // IS an Element (and has .closest). Narrowing to HTMLElement here
      // would treat glyph-icon taps as "outside" and collapse the
      // affordance the user just tried to act on.
      if (target instanceof Element && target.closest("[data-delete-affordance='true']")) {
        return;
      }
      disarmDelete();
    }

    document.addEventListener("pointerdown", handlePointerDown);
    return () => {
      document.removeEventListener("pointerdown", handlePointerDown);
    };
  }, [pendingDeleteKey, disarmDelete]);

  // Inline delete confirms (long-term rows + short-term card): disarm when leaving Memories.
  useEffect(() => {
    if (pendingDeleteKey === null) return;
    const memoryScoped =
      pendingDeleteKey.startsWith(LONG_TERM_MEMORY_ACTION_PREFIX) ||
      pendingDeleteKey.startsWith(MEMORY_CARD_DELETE_PREFIX);
    if (!memoryScoped) return;
    if (panel === "memories") return;
    disarmDelete();
  }, [panel, pendingDeleteKey, disarmDelete]);

  // Create mode: seed random color/glyph when the Bots panel opens only if
  // the compose form is still empty and the user hasn't picked a swatch/glyph
  // yet — so closing the panel mid-draft (or after a mis-tap) preserves work.
  useEffect(() => {
    if (panel !== "bots" || editingBotId) return;

    const draft = latestCreateBotDraftRef.current;
    if (
      createBotFormHasEnteredData(draft) ||
      createBotAppearanceTouchedRef.current
    ) {
      return;
    }

    setNewBotColor(randomHex(
      bots.map((bot) => bot.color?.trim() ?? "").filter((hex) => hex.length > 0)
    ));
    setNewBotGlyph(randomBotGlyph());
  }, [panel, editingBotId]);

  useEffect(() => {
    if (botProfileBuilderOpen && !newBotName.trim()) {
      setBotProfileBuilderOpen(false);
    }
  }, [botProfileBuilderOpen, newBotName]);

  // Close the color/glyph popover on any outside click or Escape. Only
  // one picker ever lives on screen (the top form in the Bots panel), so
  // a single `colorWheelOpen` flag is enough — no per-bot variant needed.
  useEffect(() => {
    if (!colorWheelOpen) return;
    function handlePointerDown(event: PointerEvent) {
      if (!isPrimaryPointerDismissal(event)) return;
      const target = event.target;
      // `Element` (not HTMLElement) is deliberate: a click inside the
      // glyph grid typically lands on an SVG <path>/<circle>, which is
      // an SVGElement — an Element subtype but NOT an HTMLElement. The
      // previous HTMLElement narrowing silently collapsed the popover
      // whenever the user hit an actual glyph icon (the whole point of
      // the grid), while clicks on gaps/padding worked fine.
      if (
        target instanceof Element &&
        target.closest("[data-color-affordance='true']")
      ) {
        return;
      }
      setColorWheelOpen(false);
    }
    function handleKey(event: KeyboardEvent) {
      if (event.key === "Escape") setColorWheelOpen(false);
    }
    document.addEventListener("pointerdown", handlePointerDown);
    document.addEventListener("keydown", handleKey);
    return () => {
      document.removeEventListener("pointerdown", handlePointerDown);
      document.removeEventListener("keydown", handleKey);
    };
  }, [colorWheelOpen]);

  async function deleteConversation(id: string) {
    setError(null);
    disarmDelete();
    // Optimistic update: drop the chat from the sidebar immediately and, if
    // it was open, clear the main pane. Roll everything back on failure.
    const previousConversations = conversations;
    const previousSelectedId = selectedId;
    const previousDetail = detail;
    const previousSessionOpinion = sessionOpinion;
    const previousBotOpinion = botOpinion;
    setConversations(list => list.filter(c => c.id !== id));
    if (selectedId === id) {
      setSelectedId(null);
      setDetail(null);
      setSessionOpinion(null);
      setBotOpinion(null);
    }
    try {
      await api(`/api/conversations/${id}`, { method: "DELETE" });
      // Resync from the server so updatedAt order / any server-side fixups
      // (e.g. race with another tab) are reflected.
      await refreshConversations();
    } catch (err) {
      setConversations(previousConversations);
      setSelectedId(previousSelectedId);
      setDetail(previousDetail);
      setSessionOpinion(previousSessionOpinion);
      setBotOpinion(previousBotOpinion);
      setError(err instanceof Error ? err.message : "Delete failed.");
    }
  }

  async function deleteConversationGroup(group: ConversationGroupSummary) {
    setError(null);
    disarmDelete();
    const previousConversations = conversations;
    const previousSelectedId = selectedId;
    const previousDetail = detail;
    const previousSessionOpinion = sessionOpinion;
    const previousBotOpinion = botOpinion;
    const previousUnreadIds = unreadConversationIds;
    const previousUnreadOrder = unreadConversationOrder;
    const previousExpandedGroupKey = expandedConversationGroupKey;
    const groupConversationIds = new Set(
      previousConversations
        .filter((conversation) => conversationGroupKey(conversation) === group.key)
        .map((conversation) => conversation.id)
    );
    const selectedGroupKey = previousDetail?.incognito
      ? null
      : previousDetail
        ? previousDetail.botId
          ? `bot:${previousDetail.botId}`
          : "default"
        : null;

    setConversations((list) =>
      list.filter((conversation) => conversationGroupKey(conversation) !== group.key)
    );
    setUnreadConversationIds((previous) => {
      const next = new Set(previous);
      for (const id of groupConversationIds) next.delete(id);
      return next;
    });
    setUnreadConversationOrder((previous) =>
      previous.filter((id) => !groupConversationIds.has(id))
    );
    setExpandedConversationGroupKey(null);
    if (selectedGroupKey === group.key) {
      setSelectedId(null);
      setDetail(null);
      setSessionOpinion(null);
      setBotOpinion(null);
    }

    try {
      const routeBotId = group.botId ? encodeURIComponent(group.botId) : "_default";
      await api(`/api/conversations/by-bot/${routeBotId}`, { method: "DELETE" });
      await refreshConversations();
      await refreshOpenMemoryViews();
    } catch (err) {
      setConversations(previousConversations);
      setSelectedId(previousSelectedId);
      setDetail(previousDetail);
      setSessionOpinion(previousSessionOpinion);
      setBotOpinion(previousBotOpinion);
      setUnreadConversationIds(previousUnreadIds);
      setUnreadConversationOrder(previousUnreadOrder);
      setExpandedConversationGroupKey(previousExpandedGroupKey);
      setError(err instanceof Error ? err.message : "Delete conversation group failed.");
    }
  }

  // Bulk-clear every chat, triggered by the hold-to-delete-all gesture.
  // Optimistically wipes the sidebar + open pane so the UI matches the
  // user's intent instantly; on failure we roll back to the previous
  // snapshot and surface the error rather than silently recovering.
  async function deleteAllConversations() {
    setError(null);
    disarmDelete();
    const previousConversations = conversations;
    const previousSelectedId = selectedId;
    const previousDetail = detail;
    const previousSessionOpinion = sessionOpinion;
    const previousBotOpinion = botOpinion;
    // Nothing to clear — short-circuit rather than fire a no-op request.
    if (previousConversations.length === 0) return;
    setConversations([]);
    setSelectedId(null);
    setDetail(null);
    setSessionOpinion(null);
    setBotOpinion(null);
    try {
      await api("/api/conversations", { method: "DELETE" });
      await refreshConversations();
    } catch (err) {
      setConversations(previousConversations);
      setSelectedId(previousSelectedId);
      setDetail(previousDetail);
      setSessionOpinion(previousSessionOpinion);
      setBotOpinion(previousBotOpinion);
      setError(err instanceof Error ? err.message : "Delete all failed.");
    }
  }

  async function deleteAllCoffeeSessions() {
    setCoffeeError(null);
    setError(null);
    disarmDelete();
    const coffeeSessionIds = coffeeSessions.map((session) => session.id);
    if (coffeeSessionIds.length === 0) return;
    const coffeeSessionIdSet = new Set(coffeeSessionIds);
    try {
      await Promise.all(
        coffeeSessionIds.map((sessionId) =>
          api(`/api/conversations/${encodeURIComponent(sessionId)}`, { method: "DELETE" })
        )
      );
      if (
        (coffeeConversation && coffeeSessionIdSet.has(coffeeConversation.id)) ||
        (coffeeSelectedSessionId && coffeeSessionIdSet.has(coffeeSelectedSessionId))
      ) {
        resetCoffeeToPicker();
      }
      if (selectedId && coffeeSessionIdSet.has(selectedId)) {
        setSelectedId(null);
        setDetail(null);
        setSessionOpinion(null);
        setBotOpinion(null);
      }
      await refreshConversations();
    } catch (err) {
      setCoffeeError(err instanceof Error ? err.message : "Delete Coffee Sessions failed.");
      await refreshConversations().catch(() => undefined);
    }
  }

  async function deleteCoffeeGroupConfirmed(groupId: string) {
    setCoffeeError(null);
    setError(null);
    disarmDelete();
    try {
      await api(`/api/coffee/groups/${encodeURIComponent(groupId)}`, { method: "DELETE" });
      if (coffeeSelectedGroupId === groupId || coffeeConversation?.coffeeGroupId === groupId) {
        resetCoffeeToPicker();
      }
      await refreshCoffeeGroups();
      await refreshConversations();
    } catch (err) {
      setCoffeeError(err instanceof Error ? err.message : "Failed to delete Coffee Group.");
      await refreshCoffeeGroups().catch(() => undefined);
      await refreshConversations().catch(() => undefined);
    }
  }

  async function runConversationSweepActionConfirmed(): Promise<void> {
    if (sweepBusy) return;
    setError(null);
    setSweepBusy(true);
    try {
      const sweepResult = await api<ConversationSweepResponse>("/api/conversations/sweep", {
        method: "POST",
        body: JSON.stringify({
          mode: view === "chat" ? "chat" : "sandbox",
        }),
      });
      const expiresAtMs = sweepResult.undoExpiresAt
        ? Date.parse(sweepResult.undoExpiresAt)
        : NaN;
      if (sweepResult.batchId && Number.isFinite(expiresAtMs)) {
        setSweepUndoToast({
          batchId: sweepResult.batchId,
          expiresAt: expiresAtMs,
        });
      } else {
        setSweepUndoToast(null);
      }
      const nextConversations = await refreshConversations();
      if (
        detailIdRef.current &&
        !nextConversations.some((conversation) => conversation.id === detailIdRef.current)
      ) {
        setSelectedId(null);
        setDetail(null);
        setSessionOpinion(null);
        setBotOpinion(null);
      }
      await refreshOpenMemoryViews();
    } catch (err) {
      setError(err instanceof Error ? err.message : "Sweep action failed.");
    } finally {
      setSweepBusy(false);
    }
  }

  async function undoConversationSweepFromToast(batchId: string): Promise<void> {
    if (sweepBusy) return;
    setError(null);
    setSweepBusy(true);
    try {
      await api("/api/conversations/sweep/undo", {
        method: "POST",
        body: JSON.stringify({ batchId }),
      });
      setSweepUndoToast((current) => (current?.batchId === batchId ? null : current));
      const nextConversations = await refreshConversations();
      if (
        detailIdRef.current &&
        !nextConversations.some((conversation) => conversation.id === detailIdRef.current)
      ) {
        setSelectedId(null);
        setDetail(null);
        setSessionOpinion(null);
        setBotOpinion(null);
      }
      await refreshOpenMemoryViews();
    } catch (err) {
      setError(err instanceof Error ? err.message : "Undo sweep failed.");
    } finally {
      setSweepBusy(false);
    }
  }

  function requestConversationSweepAction(): void {
    if (sweepBusy) return;
    if (!hasSweepEligibleConversations) return;
    setSweepConfirmOpen(true);
  }

  function buildRandomBotDraft(name = randomBotName()) {
    return {
      name,
      profile: randomBotProfile(name),
      temperature: randomBotTemperatureSetting(),
      maxTokens: randomBotReplyLengthTokens(),
      color: randomHex(
        bots.map((bot) => bot.color?.trim() ?? "").filter((hex) => hex.length > 0)
      ),
      glyph: randomBotGlyph(),
    };
  }

  function applyRandomBotDraft() {
    const draft = buildRandomBotDraft();
    setPanelNotice(null);
    setNewBotName(draft.name);
    setBotProfile(draft.profile);
    setNewBotTemperature(draft.temperature);
    setNewBotMaxTokens(draft.maxTokens);
    createBotAppearanceTouchedRef.current = true;
    setNewBotColor(draft.color);
    setNewBotGlyph(draft.glyph);
    setColorWheelOpen(false);
    setBotProfileBuilderOpen(false);
    setBotProfileActivePage("purpose");
  }

  // Reset the top form back to "create" mode with a fresh random
  // color/glyph seed. Clears draft/touch guards so the next open behaves
  // like an empty compose. Called after a successful create and when the
  // user cancels or deletes an in-progress edit.
  const resetBotForm = useCallback(() => {
    setNewBotName("");
    setBotProfile(blankBotProfile());
    setNewBotLocalModel(AUTO_MODEL_CHOICE);
    setNewBotOnlineModel(AUTO_MODEL_CHOICE);
    setNewBotLocalImageModel(AUTO_MODEL_CHOICE);
    setNewBotOpenAiImageModel(AUTO_MODEL_CHOICE);
    setNewBotOnlineEnabled(true);
    setNewBotDeleteProtected(false);
    setNewBotFlirtEnabled(false);
    setNewBotTemperature(BOT_TEMPERATURE_DEFAULT);
    setNewBotMaxTokens(BOT_REPLY_LENGTH_DEFAULT_TOKENS);
    createBotAppearanceTouchedRef.current = false;
    setNewBotColor(randomHex(
      bots.map((bot) => bot.color?.trim() ?? "").filter((hex) => hex.length > 0)
    ));
    setNewBotGlyph(randomBotGlyph());
    setColorWheelOpen(false);
    setBotProfileBuilderOpen(false);
    setBotProfileActivePage("purpose");
    setBotPreferredModelsModalOpen(false);
    setBotModelRoutingPage("chat");
    // Drop any stashed edit-mode snapshot so the next edit compares
    // against the correct starting state. Safe to always clear here:
    // the only places that hold a snapshot are paths that also call
    // resetBotForm on exit.
    editOriginalRef.current = null;
  }, []);

  // Opens the Bots panel in global/create context (Default or zoomed-out view).
  // Always starts from a fresh draft so metadata from the last edited bot
  // never bleeds into the "new bot" form.
  function openFreshBotCustomizer(): void {
    disarmDelete();
    setPanelError(null);
    setPanelNotice(null);
    setPanelBotDeleteConfirm(null);
    setSelectedBotDeleteConfirm(null);
    setEditingBotId(null);
    setBotPanelGroup(BOT_LIBRARY_FILTER_ALL);
    setBotLibraryExpanded(false);
    setBotLibraryClosing(false);
    setBotPanelLibraryEnabled(true);
    resetBotForm();
    openRightPanel("bots");
  }

  async function createBot() {
    setPanelError(null);
    setPanelNotice(null);
    const createdBotName = newBotName.trim();
    const localModel = visibleConcreteModelChoiceForProvider(
      modelCatalog,
      settings,
      "local",
      newBotLocalModel
    );
    const onlineModel = visibleConcreteModelChoiceForProvider(
      modelCatalog,
      settings,
      "openai",
      newBotOnlineModel
    );
    const localImageStored =
      newBotLocalImageModel === AUTO_MODEL_CHOICE ? "" : newBotLocalImageModel.trim();
    const openaiImageStored =
      newBotOpenAiImageModel === AUTO_MODEL_CHOICE
        ? ""
        : normalizeOpenAiImageModelId(newBotOpenAiImageModel.trim());
    try {
      await api("/api/bots", {
        method: "POST",
        body: JSON.stringify({
          name: newBotName,
          systemPrompt: serializeStoredBotPrompt(botProfile, newBotName),
          localModel: localModel === AUTO_MODEL_CHOICE ? "" : localModel,
          onlineModel: onlineModel === AUTO_MODEL_CHOICE ? "" : onlineModel,
          localImageModel: localImageStored,
          openaiImageModel: openaiImageStored,
          onlineEnabled: newBotOnlineEnabled,
          deleteProtected: newBotDeleteProtected,
          flirtEnabled: newBotFlirtEnabled,
          temperature: newBotTemperature,
          maxTokens: newBotMaxTokens,
          color: newBotColor,
          glyph: newBotGlyph,
        }),
      });
      resetBotForm();
      setPanelNotice(`${createdBotName} created.`);
      await refreshBots();
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Create bot failed.");
    }
  }

  async function deleteBot(id: string) {
    setPanelError(null);
    setPanelNotice(null);
    disarmDelete();
    // If the deleted bot was the one loaded into the top form, collapse
    // back to create mode so the editor doesn't keep pointing at a row
    // that no longer exists.
    if (editingBotId === id) {
      setEditingBotId(null);
      resetBotForm();
    }
    // Optimistic update: drop the bot from the panel immediately, and if the
    // user had it selected in the sidebar clear that too so subsequent chats
    // don't try to reference a bot that's already gone. Roll back on failure.
    const previousBots = bots;
    const previousSelectedBotId = selectedBotId;
    setBots(list => list.filter(b => b.id !== id));
    if (selectedBotId === id) {
      setSelectedBotId(null);
    }
    try {
      await api(`/api/bots/${id}`, { method: "DELETE" });
      await refreshBots();
      if (panelRef.current === "bots") {
        closePanel();
      }
    } catch (err) {
      setBots(previousBots);
      setSelectedBotId(previousSelectedBotId);
      setPanelError(err instanceof Error ? err.message : "Delete failed.");
    }
  }

  async function cloneBot(bot: Bot) {
    setPanelError(null);
    setPanelNotice(null);
    closeBotContextMenu();
    try {
      const result = await api<{ bot?: { id?: string } }>("/api/bots", {
        method: "POST",
        body: JSON.stringify({
          name: `${bot.name} (copy)`,
          systemPrompt: bot.system_prompt,
          localModel: bot.local_model ?? "",
          onlineModel: bot.online_model ?? "",
          localImageModel: bot.local_image_model ?? "",
          openaiImageModel: bot.openai_image_model ?? "",
          onlineEnabled: bot.online_enabled !== 0,
          deleteProtected: bot.delete_protected === 1,
          flirtEnabled: bot.flirt_enabled === 1,
          temperature: normalizeBotTemperature(bot.temperature),
          maxTokens: normalizeBotMaxTokens(bot.max_tokens),
          color: bot.color,
          glyph: bot.glyph,
        }),
      });
      await refreshBots();
      if (result.bot?.id) {
        setEditingBotId(result.bot.id);
        openRightPanel("bots");
        setBotPanelGroup(BOT_LIBRARY_FILTER_ALL);
        setBotLibraryExpanded(false);
        setBotLibraryClosing(false);
        setBotPanelLibraryEnabled(false);
      }
      setPanelNotice(`${bot.name} cloned.`);
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Clone bot failed.");
    }
  }

